import React, { useMemo, useState } from 'react';
import { useWasteStore } from '../store/useWasteStore';
import { analyzeMixture } from '../utils/mixtureLogic';
import { checkCompatibility } from '../utils/compatibilityChecker';
import { saveWasteLog } from '../services/wasteLogService';
import { X, Trash2, AlertTriangle, AlertOctagon, CheckCircle, Loader2 } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { CustomDialog } from './CustomDialog';

interface CartViewProps {
    onClose: () => void;
    onDisposed?: () => void;
}

export const CartView: React.FC<CartViewProps> = ({ onClose, onDisposed }) => {
    const { cart, removeFromCart, clearCart } = useWasteStore();
    const { t } = useTranslation();

    const mixtureResult = useMemo(() => analyzeMixture(cart), [cart]);
    const compatWarnings = useMemo(() => checkCompatibility(cart), [cart]);

    // Dispose flow state
    const [showDisposeModal, setShowDisposeModal] = useState(false);
    const [handlerName, setHandlerName] = useState('');
    const [memo, setMemo] = useState('');
    const [isSaving, setIsSaving] = useState(false);
    const [saveResult, setSaveResult] = useState<'success' | 'error' | null>(null);

    const [isClearDialogOpen, setIsClearDialogOpen] = useState(false);

    const handleDispose = async () => {
        setIsSaving(true);
        setSaveResult(null);
        try {
            // Calculate total volume from cart items
            const totalVol = cart.reduce((sum, item) => {
                if (item.volume) {
                    const num = parseFloat(item.volume.replace(/[^0-9.]/g, ''));
                    return sum + (isNaN(num) ? 0 : num);
                }
                return sum;
            }, 0);

            await saveWasteLog({
                chemicals: cart,
                disposal_category: t(mixtureResult.label as any) || mixtureResult.label,
                total_volume_ml: totalVol > 0 ? totalVol : undefined,
                handler_name: handlerName || undefined,
                memo: memo || undefined,
            });

            setSaveResult('success');
            // After a brief success message, clear cart and close
            setTimeout(() => {
                clearCart();
                setShowDisposeModal(false);
                setSaveResult(null);
                onClose();
                onDisposed?.();
            }, 1200);
        } catch {
            setSaveResult('error');
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-end justify-center pointer-events-none">
            {/* Backdrop */}
            <div
                className="absolute inset-0 bg-black/50 pointer-events-auto"
                onClick={onClose}
            />

            {/* Sheet Content */}
            <div
                className="relative z-10 w-full max-w-[430px] bg-white dark:bg-slate-900 rounded-t-2xl shadow-2xl overflow-hidden pointer-events-auto flex flex-col max-h-[90vh] animate-in slide-in-from-bottom duration-300"
                onClick={(e) => e.stopPropagation()}
            >

                {/* Header */}
                <div className="p-4 border-b border-gray-100 dark:border-slate-800 flex items-center justify-between bg-slate-50 dark:bg-slate-900">
                    <h3 className="font-bold text-lg text-slate-800 dark:text-white">
                        {t('cart_title')} <span className="text-blue-600 dark:text-blue-400">({cart.length})</span>
                    </h3>
                    <button onClick={onClose} className="p-1 hover:bg-gray-200 dark:hover:bg-slate-800 rounded-full transition-colors">
                        <X className="w-6 h-6 text-gray-500 dark:text-gray-400" />
                    </button>
                </div>

                {/* List of Chemicals */}
                <div className="flex-1 overflow-y-auto p-4 space-y-3 min-h-[150px]">
                    {cart.length === 0 ? (
                        <div className="text-center text-gray-400 dark:text-gray-500 py-10">
                            {t('cart_empty')}
                        </div>
                    ) : (
                        cart.map((item) => (
                            <div key={item.chemical.id} className="flex justify-between items-center p-3 border border-gray-100 dark:border-slate-700 rounded-lg bg-gray-50/50 dark:bg-slate-800/50">
                                <div>
                                    <div className="font-semibold text-slate-700 dark:text-slate-300">{item.chemical.name}</div>
                                    <div className="text-xs text-slate-500 dark:text-slate-500">{t(item.label as any)}</div>
                                    {(item.volume || item.molarity) && (
                                        <div className="text-xs text-slate-400 dark:text-slate-500 mt-0.5 font-mono">
                                            {item.volume}{item.volume && item.molarity && ' • '}{item.molarity}
                                        </div>
                                    )}
                                </div>
                                <button
                                    onClick={() => removeFromCart(item.chemical.id)}
                                    className="text-gray-400 hover:text-red-500 dark:hover:text-red-400 p-2"
                                >
                                    <Trash2 className="w-4 h-4" />
                                </button>
                            </div>
                        ))
                    )}

                    {/* ── Compatibility Warnings ── */}
                    {compatWarnings.length > 0 && (
                        <div className="space-y-2 pt-1">
                            <div className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider px-1">
                                {t('compat_title')}
                            </div>
                            {compatWarnings.map((w, idx) => {
                                const isDanger = w.severity === 'DANGER';
                                return (
                                    <div
                                        key={`${w.ruleId}-${idx}`}
                                        className={`p-3 rounded-xl border text-sm flex items-start gap-2.5 ${isDanger
                                            ? 'bg-red-50 dark:bg-red-950/40 border-red-200 dark:border-red-800/50 text-red-700 dark:text-red-300'
                                            : 'bg-amber-50 dark:bg-amber-950/30 border-amber-200 dark:border-amber-800/50 text-amber-700 dark:text-amber-300'
                                            }`}
                                    >
                                        {isDanger
                                            ? <AlertOctagon className="w-4 h-4 flex-shrink-0 mt-0.5" />
                                            : <AlertTriangle className="w-4 h-4 flex-shrink-0 mt-0.5" />
                                        }
                                        <div className="min-w-0">
                                            <div className="font-bold text-xs mb-0.5">
                                                {isDanger ? t('compat_danger') : t('compat_warning')}: {w.chemicalA} ↔ {w.chemicalB}
                                            </div>
                                            <div className="text-xs leading-snug opacity-90">
                                                {t(w.messageKey as any)}
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>

                {/* Mixture Analysis Result Footer */}
                {cart.length > 0 && (
                    <div className="p-5 border-t border-gray-100 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] text-center">
                        <h4 className="text-sm text-gray-500 dark:text-gray-400 mb-2 font-medium">{t('cart_guide_title')}</h4>

                        <div className={`p-4 rounded-xl ${mixtureResult.binColor} text-white shadow-lg mb-3`}>
                            <div className="font-bold text-lg mb-1">{t(mixtureResult.label as any)}</div>
                            <div className="text-sm opacity-90 leading-snug">{t(mixtureResult.reason as any)}</div>

                            {/* Detailed Disposal Info for Alkali+Organic */}
                            {(mixtureResult as any).disposalDetails && (
                                <div className="mt-3 pt-3 border-t border-white/20 text-xs text-left space-y-1">
                                    <div className="flex justify-between">
                                        <span className="opacity-80">{t('detail_solubility' as any)}:</span>
                                        <span className="font-bold">{(mixtureResult as any).disposalDetails.solubility}</span>
                                    </div>
                                    <div className="flex justify-between">
                                        <span className="opacity-80">{t('detail_neutralization' as any)}:</span>
                                        <span className="font-bold">{(mixtureResult as any).disposalDetails.neutralization}</span>
                                    </div>
                                </div>
                            )}
                        </div>

                        {!mixtureResult.isSafe && (
                            <div className="bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 text-xs p-2 rounded flex items-center gap-2 mb-3 text-left">
                                <AlertTriangle className="w-4 h-4 flex-shrink-0" />
                                {t('cart_safety_check')}
                            </div>
                        )}

                        {/* ── Dispose Complete Button ── */}
                        <button
                            onClick={() => setShowDisposeModal(true)}
                            className="w-full py-3 bg-blue-600 dark:bg-blue-500 text-white rounded-xl hover:bg-blue-700 dark:hover:bg-blue-600 text-sm font-semibold transition-colors shadow-md mb-2"
                        >
                            {t('btn_dispose_complete')}
                        </button>

                        <button
                            onClick={() => setIsClearDialogOpen(true)}
                            className="w-full py-3 border border-gray-200 dark:border-slate-700 text-gray-600 dark:text-gray-300 rounded-xl hover:bg-gray-50 dark:hover:bg-slate-800 text-sm font-medium transition-colors"
                        >
                            {t('btn_clear_all')}
                        </button>
                    </div>
                )}
            </div>

            {/* ── Dispose Confirmation Modal ── */}
            {showDisposeModal && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center pointer-events-auto">
                    <div className="absolute inset-0 bg-black/40" onClick={() => !isSaving && setShowDisposeModal(false)} />
                    <div
                        className="relative z-10 bg-white dark:bg-slate-800 rounded-2xl shadow-2xl w-[90%] max-w-[360px] p-6 animate-in fade-in zoom-in-95 duration-200"
                        onClick={(e) => e.stopPropagation()}
                    >
                        {saveResult === 'success' ? (
                            <div className="text-center py-4">
                                <CheckCircle className="w-12 h-12 text-green-500 mx-auto mb-3" />
                                <p className="font-semibold text-slate-800 dark:text-white">
                                    {t('dispose_success')}
                                </p>
                            </div>
                        ) : (
                            <>
                                <h3 className="font-bold text-lg text-slate-800 dark:text-white mb-1">
                                    {t('btn_dispose_complete')}
                                </h3>
                                <p className="text-sm text-slate-500 dark:text-slate-400 mb-4">
                                    {t('dispose_confirm')}
                                </p>

                                {/* Handler Name */}
                                <div className="mb-3">
                                    <input
                                        type="text"
                                        value={handlerName}
                                        onChange={(e) => setHandlerName(e.target.value)}
                                        placeholder={t('input_handler')}
                                        className="w-full px-3 py-2.5 border border-gray-200 dark:border-slate-600 rounded-lg bg-gray-50 dark:bg-slate-700 text-slate-800 dark:text-white placeholder-gray-400 dark:placeholder-gray-500 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                                    />
                                </div>

                                {/* Memo */}
                                <div className="mb-4">
                                    <textarea
                                        value={memo}
                                        onChange={(e) => setMemo(e.target.value)}
                                        placeholder={t('input_memo')}
                                        rows={2}
                                        className="w-full px-3 py-2.5 border border-gray-200 dark:border-slate-600 rounded-lg bg-gray-50 dark:bg-slate-700 text-slate-800 dark:text-white placeholder-gray-400 dark:placeholder-gray-500 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 resize-none"
                                    />
                                </div>

                                {/* Error Message */}
                                {saveResult === 'error' && (
                                    <div className="mb-3 p-2 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 text-xs rounded-lg flex items-center gap-2">
                                        <AlertTriangle className="w-3.5 h-3.5" />
                                        {t('dispose_error')}
                                    </div>
                                )}

                                {/* Action Buttons */}
                                <div className="flex gap-2">
                                    <button
                                        onClick={() => setShowDisposeModal(false)}
                                        disabled={isSaving}
                                        className="flex-1 py-2.5 border border-gray-200 dark:border-slate-600 text-slate-600 dark:text-slate-300 rounded-xl text-sm font-medium hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors"
                                    >
                                        {t('btn_cancel')}
                                    </button>
                                    <button
                                        onClick={handleDispose}
                                        disabled={isSaving}
                                        className="flex-1 py-2.5 bg-blue-600 dark:bg-blue-500 text-white rounded-xl text-sm font-semibold hover:bg-blue-700 dark:hover:bg-blue-600 transition-colors flex items-center justify-center gap-1.5"
                                    >
                                        {isSaving
                                            ? <Loader2 className="w-4 h-4 animate-spin" />
                                            : t('btn_confirm')
                                        }
                                    </button>
                                </div>
                            </>
                        )}
                    </div>
                </div>
            )}

            <CustomDialog
                isOpen={isClearDialogOpen}
                onClose={() => setIsClearDialogOpen(false)}
                title={t('btn_clear_all')}
                description={t('cart_confirm_clear')}
                type="confirm"
                isDestructive={true}
                onConfirm={() => {
                    clearCart();
                    setIsClearDialogOpen(false);
                }}
            />
        </div>
    );
};

/**
 * Inventory Registration Modal
 * Allows users to register a product from search results into inventory.
 * When "cabinet" is chosen, actually auto-places the item on a shelf.
 */

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { X, Package, MapPin, Plus, Check, Loader2, ChevronDown, ArrowRight } from 'lucide-react';
import type { MediaProduct } from '../services/mediaProductService';
import type { Cabinet } from '../services/cabinetService';
import { cabinetService } from '../services/cabinetService';
import {
    inventoryService,
    storageLocationService,
    type StorageLocation,
} from '../services/inventoryService';
import { useFridgeStore } from '../store/fridgeStore';
import type { ReagentPlacement, ReagentTemplateType } from '../types/fridge';

interface InventoryRegistrationModalProps {
    product: MediaProduct;
    isOpen: boolean;
    onClose: () => void;
    onSuccess?: () => void;
    /** Called when the user wants to navigate to the cabinet to see the placed item */
    onNavigateToCabinet?: (cabinetId: string, itemId: string) => void;
}

export const InventoryRegistrationModal: React.FC<InventoryRegistrationModalProps> = ({
    product,
    isOpen,
    onClose,
    onSuccess,
    onNavigateToCabinet,
}) => {
    const { t } = useTranslation();

    // Form state
    const [selectedProductNumber, setSelectedProductNumber] = useState<string>('');
    const [quantity, setQuantity] = useState(1);
    const [capacity, setCapacity] = useState('');
    const [storageType, setStorageType] = useState<'cabinet' | 'other'>('other');
    const [selectedCabinetId, setSelectedCabinetId] = useState<string>('');
    const [selectedLocationId, setSelectedLocationId] = useState<string>('');
    const [memo, setMemo] = useState('');

    // Data
    const [cabinets, setCabinets] = useState<Cabinet[]>([]);
    const [locations, setLocations] = useState<StorageLocation[]>([]);

    // New location input
    const [showNewLocation, setShowNewLocation] = useState(false);
    const [newLocationName, setNewLocationName] = useState('');

    // Status
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [successState, setSuccessState] = useState<{
        type: 'other' | 'cabinet';
        cabinetId?: string;
        itemId?: string;
        shelfLevel?: number;
    } | null>(null);
    const [error, setError] = useState<string | null>(null);

    // Load cabinets and storage locations on mount
    useEffect(() => {
        if (!isOpen) return;
        loadData();
    }, [isOpen]);

    // Auto-select first product number if only one
    useEffect(() => {
        if (product.product_numbers && product.product_numbers.length === 1) {
            setSelectedProductNumber(product.product_numbers[0]);
        }
    }, [product]);

    const loadData = async () => {
        const [cabs, locs] = await Promise.all([
            cabinetService.getCabinets(),
            storageLocationService.getLocations(),
        ]);
        setCabinets(cabs);
        setLocations(locs);

        // Auto-select first location if available
        if (locs.length > 0 && !selectedLocationId) {
            setSelectedLocationId(locs[0].id);
        }
    };

    const handleAddLocation = async () => {
        if (!newLocationName.trim()) return;
        const loc = await storageLocationService.addLocation(newLocationName.trim());
        if (loc) {
            setLocations(prev => [...prev, loc]);
            setSelectedLocationId(loc.id);
            setNewLocationName('');
            setShowNewLocation(false);
        }
    };

    const resetForm = () => {
        setSuccessState(null);
        setQuantity(1);
        setCapacity('');
        setMemo('');
        setSelectedProductNumber('');
        setError(null);
    };

    const handleSubmit = async () => {
        setIsSubmitting(true);
        setError(null);

        try {
            // 1. Register in inventory table
            const result = await inventoryService.createItem({
                name: product.product_name || 'Unknown',
                brand: product.brand || undefined,
                product_number: selectedProductNumber || undefined,
                quantity,
                capacity: capacity || undefined,
                storage_type: storageType,
                cabinet_id: storageType === 'cabinet' ? selectedCabinetId : undefined,
                storage_location_id: storageType === 'other' ? selectedLocationId : undefined,
                product_id: product.id,
                memo: memo || undefined,
            });

            if (!result) {
                setError(t('inventory_error'));
                return;
            }

            // 2. If cabinet storage, actually place the reagent on a shelf
            if (storageType === 'cabinet' && selectedCabinetId) {
                const placedItemId = await placeToCabinet();
                if (placedItemId) {
                    setSuccessState({
                        type: 'cabinet',
                        cabinetId: selectedCabinetId,
                        itemId: placedItemId,
                        shelfLevel: useFridgeStore.getState().autoPlaceResult?.shelfLevel,
                    });
                } else {
                    // Inventory registered but no space in cabinet
                    setSuccessState({ type: 'cabinet', cabinetId: selectedCabinetId });
                    setError(t('reagent_no_space'));
                }
            } else {
                // Other storage — simple success, auto-close after delay
                setSuccessState({ type: 'other' });
                setTimeout(() => {
                    onSuccess?.();
                    onClose();
                    resetForm();
                }, 1200);
            }
        } catch {
            setError(t('inventory_error'));
        } finally {
            setIsSubmitting(false);
        }
    };

    /** Load the target cabinet into fridgeStore, auto-place, and save */
    const placeToCabinet = async (): Promise<string | null> => {
        const store = useFridgeStore.getState();

        // Load the cabinet data
        await store.loadCabinet(selectedCabinetId);

        // Determine template type based on capacity string
        const template: ReagentTemplateType = guessTemplate(capacity);

        // Build reagent placement data
        const itemData: Omit<ReagentPlacement, 'shelfId' | 'position' | 'depthPosition'> = {
            id: '', // autoPlaceReagent will assign a new UUID
            reagentId: product.id,
            name: product.product_name || 'Unknown',
            width: getWidthForTemplate(template),
            template,
            isAcidic: false,
            isBasic: false,
            hCodes: [],
            notes: memo || undefined,
            casNo: undefined,
            capacity: capacity || undefined,
            productNumber: selectedProductNumber || undefined,
            brand: product.brand || undefined,
        };

        const placeResult = useFridgeStore.getState().autoPlaceReagent(itemData);

        if (placeResult) {
            // Save the cabinet state with the new item
            await useFridgeStore.getState().saveCabinet();
            // Log the activity
            await cabinetService.logActivity(
                selectedCabinetId,
                'add',
                product.product_name || 'Unknown',
            );
            return placeResult.itemId;
        }

        return null;
    };

    const handleGoToCabinet = () => {
        if (successState?.cabinetId && successState?.itemId && onNavigateToCabinet) {
            onNavigateToCabinet(successState.cabinetId, successState.itemId);
        }
        onClose();
        resetForm();
    };

    const handleCloseAfterSuccess = () => {
        onSuccess?.();
        onClose();
        resetForm();
    };

    if (!isOpen) return null;

    const productNumbers = product.product_numbers?.filter(Boolean) || [];
    const isSuccess = successState !== null;

    return (
        <div className="fixed inset-0 z-50 flex items-end justify-center sm:items-center">
            {/* Backdrop */}
            <div
                className="absolute inset-0 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200"
                onClick={() => { if (!isSuccess) onClose(); }}
            />

            {/* Modal */}
            <div className="relative w-full max-w-[430px] max-h-[85vh] bg-white dark:bg-slate-900 rounded-t-2xl sm:rounded-2xl shadow-2xl animate-in slide-in-from-bottom-4 duration-300 flex flex-col overflow-hidden">
                {/* Header */}
                <div className="flex items-center justify-between px-5 py-4 border-b border-gray-100 dark:border-slate-800 flex-shrink-0">
                    <div className="flex items-center gap-2">
                        <div className="p-1.5 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg">
                            <Package className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
                        </div>
                        <h2 className="text-lg font-bold text-slate-900 dark:text-slate-100">
                            {t('inventory_register_title')}
                        </h2>
                    </div>
                    <button
                        onClick={() => { if (isSuccess) handleCloseAfterSuccess(); else onClose(); }}
                        className="p-2 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-xl transition-colors"
                    >
                        <X className="w-5 h-5 text-gray-500" />
                    </button>
                </div>

                {/* Success overlay */}
                {isSuccess && (
                    <div className="absolute inset-0 z-10 flex flex-col items-center justify-center bg-white/95 dark:bg-slate-900/95 animate-in fade-in duration-200 px-6">
                        <div className="w-16 h-16 bg-emerald-100 dark:bg-emerald-900/30 rounded-full flex items-center justify-center mb-4 animate-in zoom-in duration-300">
                            <Check className="w-8 h-8 text-emerald-600 dark:text-emerald-400" />
                        </div>
                        <p className="text-lg font-semibold text-emerald-700 dark:text-emerald-300 mb-2 text-center">
                            {t('inventory_success')}
                        </p>

                        {/* Cabinet placement result */}
                        {successState.type === 'cabinet' && successState.itemId && successState.shelfLevel && (
                            <p className="text-sm text-slate-500 dark:text-slate-400 mb-6 text-center">
                                {t('reagent_placed_toast', {
                                    name: product.product_name || '',
                                    level: successState.shelfLevel,
                                })}
                            </p>
                        )}

                        {/* No space warning */}
                        {successState.type === 'cabinet' && !successState.itemId && error && (
                            <p className="text-sm text-amber-600 dark:text-amber-400 mb-6 text-center">
                                {error}
                            </p>
                        )}

                        {/* Action buttons */}
                        <div className="flex flex-col gap-2 w-full max-w-[280px]">
                            {/* Go to cabinet button (only if placement was successful) */}
                            {successState.type === 'cabinet' && successState.itemId && onNavigateToCabinet && (
                                <button
                                    onClick={handleGoToCabinet}
                                    className="w-full py-3 px-4 bg-gradient-to-r from-emerald-500 to-teal-500 hover:from-emerald-600 hover:to-teal-600 text-white font-semibold rounded-xl transition-all active:scale-[0.98] flex items-center justify-center gap-2 shadow-lg shadow-emerald-200 dark:shadow-emerald-900/20"
                                >
                                    {t('inventory_go_to_cabinet')}
                                    <ArrowRight className="w-4 h-4" />
                                </button>
                            )}

                            {/* Close / stay button */}
                            <button
                                onClick={handleCloseAfterSuccess}
                                className={`w-full py-3 px-4 font-medium rounded-xl transition-all active:scale-[0.98] ${successState.type === 'cabinet' && successState.itemId
                                    ? 'bg-gray-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-gray-200 dark:hover:bg-slate-700'
                                    : 'bg-gradient-to-r from-emerald-500 to-teal-500 text-white'
                                    }`}
                            >
                                {t('btn_close')}
                            </button>
                        </div>
                    </div>
                )}

                {/* Body */}
                <div className="flex-1 overflow-y-auto px-5 py-4 space-y-5">
                    {/* Product Info (read-only) */}
                    <div className="bg-gray-50 dark:bg-slate-800/50 rounded-xl p-4 space-y-2">
                        <div className="flex items-start gap-3">
                            {product.thumbnail_url && (
                                <img
                                    src={product.thumbnail_url}
                                    alt=""
                                    className="w-14 h-14 rounded-lg object-contain bg-white dark:bg-slate-700 flex-shrink-0"
                                />
                            )}
                            <div className="min-w-0 flex-1">
                                <p className="font-semibold text-slate-900 dark:text-slate-100 text-sm leading-tight line-clamp-2">
                                    {product.product_name || 'Unknown Product'}
                                </p>
                                {product.brand && (
                                    <span className="inline-block mt-1 px-2 py-0.5 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-400 text-xs font-medium rounded-full">
                                        {product.brand}
                                    </span>
                                )}
                            </div>
                        </div>
                    </div>

                    {/* Product Number Selection */}
                    {productNumbers.length > 0 && (
                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                                {t('inventory_product_number')}
                            </label>
                            {productNumbers.length === 1 ? (
                                <div className="px-3 py-2.5 bg-gray-50 dark:bg-slate-800 rounded-xl text-sm text-slate-700 dark:text-slate-300 border border-gray-200 dark:border-slate-700">
                                    {productNumbers[0]}
                                </div>
                            ) : (
                                <div className="relative">
                                    <select
                                        value={selectedProductNumber}
                                        onChange={(e) => setSelectedProductNumber(e.target.value)}
                                        className="w-full px-3 py-2.5 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-sm text-slate-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent appearance-none pr-8"
                                    >
                                        <option value="">{t('inventory_select_product_number')}</option>
                                        {productNumbers.map((num) => (
                                            <option key={num} value={num}>{num}</option>
                                        ))}
                                    </select>
                                    <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
                                </div>
                            )}
                        </div>
                    )}

                    {/* Quantity & Capacity Row */}
                    <div className="grid grid-cols-2 gap-3">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                                {t('inventory_quantity')}
                            </label>
                            <div className="flex items-center h-[46px] border border-gray-200 dark:border-slate-700 rounded-xl overflow-hidden bg-white dark:bg-slate-800">
                                <button
                                    onClick={() => setQuantity(Math.max(1, quantity - 1))}
                                    className="px-3 h-full text-lg font-medium text-slate-500 hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors"
                                >
                                    −
                                </button>
                                <input
                                    type="number"
                                    value={quantity}
                                    onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                                    className="flex-1 text-center text-sm font-semibold bg-transparent text-slate-900 dark:text-slate-100 focus:outline-none [appearance:textfield] [&::-webkit-outer-spin-button]:appearance-none [&::-webkit-inner-spin-button]:appearance-none"
                                    min={1}
                                />
                                <button
                                    onClick={() => setQuantity(quantity + 1)}
                                    className="px-3 h-full text-lg font-medium text-slate-500 hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors"
                                >
                                    +
                                </button>
                            </div>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                                {t('inventory_capacity')}
                            </label>
                            <input
                                type="text"
                                value={capacity}
                                onChange={(e) => setCapacity(e.target.value)}
                                placeholder={t('inventory_capacity_placeholder')}
                                className="w-full h-[46px] px-3 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-sm text-slate-900 dark:text-slate-100 placeholder-gray-400 dark:placeholder-gray-500 focus:ring-2 focus:ring-emerald-500 focus:border-transparent"
                            />
                        </div>
                    </div>

                    {/* Storage Type */}
                    <div>
                        <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                            <MapPin className="w-4 h-4 inline mr-1 -mt-0.5" />
                            {t('inventory_storage_type')}
                        </label>
                        <div className="grid grid-cols-2 gap-2 mb-3">
                            <button
                                onClick={() => setStorageType('cabinet')}
                                className={`px-4 py-3 rounded-xl border text-sm font-medium transition-all ${storageType === 'cabinet'
                                    ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-300 dark:border-emerald-700 text-emerald-700 dark:text-emerald-300 ring-2 ring-emerald-500/20'
                                    : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:border-gray-300 dark:hover:border-slate-600'
                                    }`}
                            >
                                📦 {t('inventory_storage_cabinet')}
                            </button>
                            <button
                                onClick={() => setStorageType('other')}
                                className={`px-4 py-3 rounded-xl border text-sm font-medium transition-all ${storageType === 'other'
                                    ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-300 dark:border-emerald-700 text-emerald-700 dark:text-emerald-300 ring-2 ring-emerald-500/20'
                                    : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:border-gray-300 dark:hover:border-slate-600'
                                    }`}
                            >
                                📍 {t('inventory_storage_other')}
                            </button>
                        </div>

                        {/* Cabinet selector */}
                        {storageType === 'cabinet' && (
                            <div className="relative animate-in fade-in slide-in-from-top-1 duration-200">
                                <select
                                    value={selectedCabinetId}
                                    onChange={(e) => setSelectedCabinetId(e.target.value)}
                                    className="w-full px-3 py-2.5 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-sm text-slate-900 dark:text-slate-100 focus:ring-2 focus:ring-emerald-500 focus:border-transparent appearance-none pr-8"
                                >
                                    <option value="">{t('inventory_select_cabinet')}</option>
                                    {cabinets.map((cab) => (
                                        <option key={cab.id} value={cab.id}>
                                            {cab.name}{cab.location ? ` (${cab.location})` : ''}
                                        </option>
                                    ))}
                                </select>
                                <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
                            </div>
                        )}

                        {/* Storage location selector */}
                        {storageType === 'other' && (
                            <div className="animate-in fade-in slide-in-from-top-1 duration-200 space-y-2">
                                {/* Location chips */}
                                <div className="flex flex-wrap gap-2">
                                    {locations.map((loc) => (
                                        <button
                                            key={loc.id}
                                            onClick={() => setSelectedLocationId(loc.id)}
                                            className={`px-3 py-2 rounded-xl text-sm font-medium transition-all ${selectedLocationId === loc.id
                                                ? 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-300 ring-2 ring-emerald-500/30'
                                                : 'bg-gray-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:bg-gray-200 dark:hover:bg-slate-700'
                                                }`}
                                        >
                                            {loc.icon} {loc.name}
                                        </button>
                                    ))}

                                    {/* Add new location button */}
                                    {!showNewLocation && (
                                        <button
                                            onClick={() => setShowNewLocation(true)}
                                            className="px-3 py-2 rounded-xl text-sm font-medium bg-gray-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 hover:bg-gray-200 dark:hover:bg-slate-700 transition-colors border-2 border-dashed border-gray-300 dark:border-slate-600"
                                        >
                                            <Plus className="w-3.5 h-3.5 inline mr-1 -mt-0.5" />
                                            {t('inventory_add_location')}
                                        </button>
                                    )}
                                </div>

                                {/* New location input */}
                                {showNewLocation && (
                                    <div className="flex gap-2 animate-in fade-in duration-200">
                                        <input
                                            type="text"
                                            value={newLocationName}
                                            onChange={(e) => setNewLocationName(e.target.value)}
                                            placeholder={t('inventory_add_location_placeholder')}
                                            className="flex-1 px-3 py-2 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-sm text-slate-900 dark:text-slate-100 placeholder-gray-400 focus:ring-2 focus:ring-emerald-500 focus:border-transparent"
                                            autoFocus
                                            onKeyDown={(e) => {
                                                if (e.key === 'Enter') handleAddLocation();
                                                if (e.key === 'Escape') setShowNewLocation(false);
                                            }}
                                        />
                                        <button
                                            onClick={handleAddLocation}
                                            disabled={!newLocationName.trim()}
                                            className="px-4 py-2 bg-emerald-500 text-white rounded-xl text-sm font-medium disabled:opacity-40 hover:bg-emerald-600 transition-colors"
                                        >
                                            <Plus className="w-4 h-4" />
                                        </button>
                                        <button
                                            onClick={() => { setShowNewLocation(false); setNewLocationName(''); }}
                                            className="px-3 py-2 bg-gray-100 dark:bg-slate-800 text-gray-500 rounded-xl text-sm hover:bg-gray-200 dark:hover:bg-slate-700 transition-colors"
                                        >
                                            <X className="w-4 h-4" />
                                        </button>
                                    </div>
                                )}
                            </div>
                        )}
                    </div>

                    {/* Memo */}
                    <div>
                        <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                            {t('inventory_memo')}
                        </label>
                        <textarea
                            value={memo}
                            onChange={(e) => setMemo(e.target.value)}
                            placeholder={t('inventory_memo_placeholder')}
                            rows={2}
                            className="w-full px-3 py-2.5 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl text-sm text-slate-900 dark:text-slate-100 placeholder-gray-400 dark:placeholder-gray-500 focus:ring-2 focus:ring-emerald-500 focus:border-transparent resize-none"
                        />
                    </div>

                    {/* Error message (only shown during form, not in success overlay) */}
                    {error && !isSuccess && (
                        <div className="text-sm text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20 px-3 py-2 rounded-lg">
                            {error}
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="px-5 py-4 border-t border-gray-100 dark:border-slate-800 flex-shrink-0">
                    <button
                        onClick={handleSubmit}
                        disabled={isSubmitting || isSuccess}
                        className="w-full py-3.5 bg-gradient-to-r from-emerald-500 to-teal-500 hover:from-emerald-600 hover:to-teal-600 text-white font-semibold rounded-xl transition-all active:scale-[0.98] disabled:opacity-60 disabled:active:scale-100 flex items-center justify-center gap-2 shadow-lg shadow-emerald-200 dark:shadow-emerald-900/20"
                    >
                        {isSubmitting ? (
                            <>
                                <Loader2 className="w-5 h-5 animate-spin" />
                                {t('inventory_registering')}
                            </>
                        ) : (
                            <>
                                <Package className="w-5 h-5" />
                                {t('inventory_register_btn')}
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
};

// ── Helpers ─────────────────────────────────────────────

/** Guess a bottle template type from the capacity string */
function guessTemplate(capacity: string): ReagentTemplateType {
    if (!capacity) return 'A';
    const lower = capacity.toLowerCase();
    const numMatch = lower.match(/(\d+)/);
    const num = numMatch ? parseInt(numMatch[1]) : 0;

    if (lower.includes('kg') || num >= 2500) return 'D'; // Large box
    if (lower.includes('l') && !lower.includes('ml')) return 'C'; // Large bottle
    if (num >= 500) return 'C';
    if (num >= 100) return 'A';
    return 'B'; // Small
}

/** Get width percentage for a template */
function getWidthForTemplate(template: ReagentTemplateType): number {
    switch (template) {
        case 'A': return 8;
        case 'B': return 6;
        case 'C': return 12;
        case 'D': return 14;
        default: return 8;
    }
}

export default InventoryRegistrationModal;

import React, { useState, useEffect } from 'react';
import { X, Search, Plus, Check, Loader2, AlertCircle, Users, Settings } from 'lucide-react';
import { labService } from '../services/labService';
import { useLabStore } from '../store/useLabStore';
import type { Lab } from '../store/useLabStore';

interface LabManagementModalProps {
    onClose: () => void;
}

export const LabManagementModal: React.FC<LabManagementModalProps> = ({ onClose }) => {
    const [view, setView] = useState<'menu' | 'create' | 'search' | 'members' | 'settings'>('menu');
    const [query, setQuery] = useState('');
    const [searchResults, setSearchResults] = useState<Lab[]>([]);
    const [members, setMembers] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [createName, setCreateName] = useState('');
    const [createPassword, setCreatePassword] = useState('');
    const [createNickname, setCreateNickname] = useState('');

    // For joining a lab
    const [selectedLabId, setSelectedLabId] = useState<string | null>(null);
    const [selectedRole, setSelectedRole] = useState<'researcher' | 'student'>('researcher');
    const [joinPassword, setJoinPassword] = useState('');
    const [joinNickname, setJoinNickname] = useState('');

    // For settings
    const [settingsName, setSettingsName] = useState('');
    const [settingsPassword, setSettingsPassword] = useState('');

    const { myLabs, setMyLabs, currentLabId, setCurrentLabId } = useLabStore();

    const currentRole = myLabs.find(m => m.lab_id === currentLabId)?.role;

    const loadMembers = async () => {
        setIsLoading(true);
        setError(null);
        try {
            const data = await labService.getLabMembers(currentLabId!);
            setMembers(data);
        } catch (err: any) {
            setError(err.message || '멤버 목록을 불러오지 못했습니다.');
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        if (view === 'members' && currentLabId) {
            loadMembers();
        }
    }, [view, currentLabId]);

    const handleRoleChange = async (userId: string, newRole: string) => {
        if (!currentLabId) return;
        setIsLoading(true);
        try {
            await labService.updateMemberRole(currentLabId, userId, newRole);
            await loadMembers(); // refresh
        } catch (err: any) {
            setError(err.message || "권한 변경에 실패했습니다.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleRemoveMember = async (userId: string) => {
        if (!currentLabId || !window.confirm("정말 이 사용자를 강퇴하시겠습니까? (이 작업은 되돌릴 수 없습니다.)")) return;
        setIsLoading(true);
        try {
            await labService.removeMember(currentLabId, userId);
            await loadMembers(); // refresh
        } catch (err: any) {
            setError(err.message || "맴버 강퇴에 실패했습니다.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleSearch = async (e?: React.FormEvent) => {
        e?.preventDefault();
        if (!query.trim()) return;
        setIsLoading(true);
        setError(null);
        try {
            const results = await labService.searchLabs(query);
            setSearchResults(results);
        } catch (err: any) {
            setError(err.message || "Failed to search labs");
        } finally {
            setIsLoading(false);
        }
    };

    const handleCreate = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!createName.trim() || !createNickname.trim()) return;
        setIsLoading(true);
        setError(null);
        try {
            const newLab = await labService.createLab(createName, createPassword, createNickname);
            // update state
            const updatedLabs = await labService.getMyLabs();
            setMyLabs(updatedLabs);
            setCurrentLabId(newLab.id);
            onClose();
        } catch (err: any) {
            setError(err.message || "Failed to create lab");
        } finally {
            setIsLoading(false);
        }
    };

    const handleJoin = async () => {
        if (!selectedLabId || !joinNickname.trim()) return;
        setIsLoading(true);
        setError(null);
        try {
            await labService.joinLab(selectedLabId!, selectedRole, joinPassword, joinNickname);
            const updatedLabs = await labService.getMyLabs();
            setMyLabs(updatedLabs);
            setCurrentLabId(selectedLabId);
            onClose();
        } catch (err: any) {
            if (err.code === '23505') {
                setError("이미 이 연구실에 가입되어 있습니다.");
            } else {
                setError(err.message || "가입에 실패했습니다.");
            }
        } finally {
            setIsLoading(false);
        }
    };

    const handleUpdateSettings = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!currentLabId || !settingsName.trim()) return;
        setIsLoading(true);
        setError(null);
        try {
            await labService.updateLab(currentLabId, {
                name: settingsName,
                ...(settingsPassword ? { join_password: settingsPassword } : { join_password: '' })
            });
            // Update local state to reflect changes instantly
            const updatedLabs = await labService.getMyLabs();
            setMyLabs(updatedLabs);
            alert("연구실 설정이 저장되었습니다.");
            setView('menu');
        } catch (err: any) {
            setError(err.message || "설정 변경에 실패했습니다.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteLab = async () => {
        if (!currentLabId) return;
        const confirm1 = window.confirm(`정말 "${settingsName}" 연구실을 삭제하시겠습니까?\n이 작업은 되돌릴 수 없으며, 모든 데이터가 삭제될 수 있습니다.`);
        if (!confirm1) return;

        const confirm2 = window.prompt(`삭제 확인을 위해 연구실 이름 "${settingsName}"을(를) 정확히 입력해주세요.`);
        if (confirm2 !== settingsName) {
            alert("연구실 이름이 일치하지 않습니다. 삭제가 취소되었습니다.");
            return;
        }

        setIsLoading(true);
        setError(null);
        try {
            await labService.deleteLab(currentLabId);
            const updatedLabs = await labService.getMyLabs();
            setMyLabs(updatedLabs);
            setCurrentLabId(null);
            alert("연구실이 삭제되었습니다.");
            onClose();
        } catch (err: any) {
            setError(err.message || "연구실 삭제에 실패했습니다.");
            setIsLoading(false);
        }
    };

    const openSettings = () => {
        const lab = myLabs.find(m => m.lab_id === currentLabId)?.lab as any; // Temporary cast since we didn't add join_password to Lab type globally yet.
        setSettingsName(lab?.name || '');
        setSettingsPassword(lab?.join_password || '');
        setView('settings');
    };

    return (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-5 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="w-full max-w-[380px] bg-white dark:bg-slate-900 rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[80vh]">

                <div className="p-4 border-b border-gray-100 dark:border-slate-800 flex justify-between items-center shrink-0">
                    <h3 className="font-bold text-lg text-slate-800 dark:text-white">
                        {view === 'menu' && '연구실 관리'}
                        {view === 'create' && '새 연구실 만들기'}
                        {view === 'search' && '연구실 검색 / 가입'}
                        {view === 'members' && '멤버 관리'}
                        {view === 'settings' && '연구실 설정'}
                    </h3>
                    <button onClick={onClose} className="p-1 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-full transition-colors">
                        <X className="w-5 h-5 text-gray-500" />
                    </button>
                </div>

                <div className="p-5 flex-1 overflow-y-auto">
                    {error && (
                        <div className="mb-4 flex items-center gap-2 text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20 p-3 rounded-lg text-sm">
                            <AlertCircle className="w-4 h-4 shrink-0" />
                            {error}
                        </div>
                    )}

                    {view === 'menu' && (
                        <div className="space-y-3">
                            {currentLabId && (
                                <button
                                    onClick={() => setView('members')}
                                    className="w-full flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl transition-colors border border-slate-200 dark:border-slate-700"
                                >
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400 rounded-lg">
                                            <Users className="w-5 h-5" />
                                        </div>
                                        <div className="text-left">
                                            <div className="font-semibold text-slate-800 dark:text-slate-200">현재 연구실 멤버 관리</div>
                                            <div className="text-xs text-slate-500 dark:text-slate-400">연구실에 소속된 멤버 목록 확인 및 권한 설정</div>
                                        </div>
                                    </div>
                                </button>
                            )}
                            {currentLabId && currentRole === 'admin' && (
                                <button
                                    onClick={openSettings}
                                    className="w-full flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl transition-colors border border-slate-200 dark:border-slate-700"
                                >
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300 rounded-lg">
                                            <Settings className="w-5 h-5" />
                                        </div>
                                        <div className="text-left">
                                            <div className="font-semibold text-slate-800 dark:text-slate-200">연구실 설정</div>
                                            <div className="text-xs text-slate-500 dark:text-slate-400">이름 및 가입 비밀번호 변경</div>
                                        </div>
                                    </div>
                                </button>
                            )}
                            <button
                                onClick={() => setView('search')}
                                className="w-full flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl transition-colors border border-slate-200 dark:border-slate-700"
                            >
                                <div className="flex items-center gap-3">
                                    <div className="p-2 bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg">
                                        <Search className="w-5 h-5" />
                                    </div>
                                    <div className="text-left">
                                        <div className="font-semibold text-slate-800 dark:text-slate-200">기존 연구실 가입</div>
                                        <div className="text-xs text-slate-500 dark:text-slate-400">연구실을 검색하고 소속으로 가입합니다.</div>
                                    </div>
                                </div>
                            </button>
                            <button
                                onClick={() => setView('create')}
                                className="w-full flex items-center justify-between p-4 bg-slate-50 dark:bg-slate-800 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl transition-colors border border-slate-200 dark:border-slate-700"
                            >
                                <div className="flex items-center gap-3">
                                    <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 rounded-lg">
                                        <Plus className="w-5 h-5" />
                                    </div>
                                    <div className="text-left">
                                        <div className="font-semibold text-slate-800 dark:text-slate-200">새 연구실 생성</div>
                                        <div className="text-xs text-slate-500 dark:text-slate-400">새로운 그룹을 만들고 관리자가 됩니다.</div>
                                    </div>
                                </div>
                            </button>

                            <div className="mt-8">
                                <h4 className="font-semibold text-sm text-slate-500 mb-2 px-1">소속된 연구실 목록</h4>
                                {myLabs.length === 0 ? (
                                    <div className="text-sm text-slate-400 italic px-1">가입된 연구실이 없습니다.</div>
                                ) : (
                                    <ul className="space-y-2">
                                        {myLabs.map(ml => (
                                            <li key={ml.lab_id} className="flex justify-between items-center p-3 rounded-lg bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800">
                                                <span className="font-medium text-slate-700 dark:text-slate-200">{ml.lab?.name}</span>
                                                <span className="text-xs bg-slate-100 dark:bg-slate-800 px-2 py-1 rounded text-slate-600 dark:text-slate-400 capitalize">{ml.role}</span>
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </div>
                        </div>
                    )}

                    {view === 'create' && (
                        <form onSubmit={handleCreate} className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">연구실 이름</label>
                                <input
                                    type="text"
                                    value={createName}
                                    onChange={e => setCreateName(e.target.value)}
                                    placeholder="예: 생명공학 제1연구실"
                                    className="w-full px-3 py-2 border border-slate-300 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-800 focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 dark:text-slate-100"
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">내 닉네임 / 이름</label>
                                <input
                                    type="text"
                                    value={createNickname}
                                    onChange={e => setCreateNickname(e.target.value)}
                                    placeholder="예: 홍길동"
                                    className="w-full px-3 py-2 border border-slate-300 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-800 focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 dark:text-slate-100"
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">입장 비밀번호 (선택)</label>
                                <input
                                    type="password"
                                    value={createPassword}
                                    onChange={e => setCreatePassword(e.target.value)}
                                    placeholder="설정하지 않으면 누구나 가입할 수 있습니다."
                                    className="w-full px-3 py-2 border border-slate-300 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-800 focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 dark:text-slate-100"
