                            </div>
                        </form>
                    )}

                    {view === 'search' && (
                        <div className="space-y-4">
                            <form onSubmit={handleSearch} className="relative">
                                <input
                                    type="text"
                                    value={query}
                                    onChange={e => setQuery(e.target.value)}
                                    placeholder="연구실 이름 검색"
