                                    </div>
                                    <button
                                        onClick={handleJoin}
                                        disabled={isLoading || !joinNickname.trim()}
                                        className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium transition-colors disabled:opacity-50 flex justify-center items-center"
