                            {searchResults.length === 0 && query && !isLoading && (
                                <div className="text-center py-8 text-slate-500 dark:text-slate-400 text-sm">
                                    검색 결과가 없습니다.
                                </div>
                            )}

                            <div className="pt-2">
                                <button type="button" onClick={() => { setView('menu'); setSelectedLabId(null); setJoinPassword(''); setJoinNickname(''); }} className="w-full py-2 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 rounded-lg font-medium hover:bg-slate-200 transition-colors">
                                    뒤로 가기
                                </button>
                            </div>
                        </div>
                    )}

                    {view === 'members' && (
                        <div className="space-y-4">
                            {isLoading && members.length === 0 ? (
                                <div className="flex justify-center p-8"><Loader2 className="w-6 h-6 animate-spin text-slate-400" /></div>
                            ) : members.length === 0 ? (
                                <div className="text-center py-8 text-slate-500">멤버가 없습니다.</div>
                            ) : (
                                <ul className="space-y-3">
                                    {members.map(member => (
                                        <li key={member.user_id} className="p-3 bg-slate-50 dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700">
                                            <div className="flex justify-between items-start mb-2">
                                                <div className="flex flex-col">
                                                    <div className="flex items-center gap-2">
                                                        <span className="font-medium text-slate-800 dark:text-slate-200">
                                                            {member.nickname || member.email || '알 수 없는 사용자'}
                                                        </span>
                                                        {member.nickname && member.email && (
                                                            <span className="text-xs text-slate-400 dark:text-slate-500">
                                                                ({member.email})
                                                            </span>
                                                        )}
                                                    </div>
                                                    <span className="text-xs text-slate-500 mt-0.5">가입일: {new Date(member.joined_at).toLocaleDateString()}</span>
                                                </div>
                                                <span className={`text-xs px-2 py-1 rounded font-medium ${member.role === 'admin' ? 'bg-purple-100 text-purple-700 dark:bg-purple-900/40 dark:text-purple-300' : 'bg-slate-200 text-slate-700 dark:bg-slate-700 dark:text-slate-300'}`}>
                                                    {member.role.toUpperCase()}
                                                </span>
                                            </div>

                                            {currentRole === 'admin' && member.role !== 'admin' && ( // Admins can't demote themselves easily here to avoid 0 admins scenario
                                                <div className="flex gap-2 mt-3 pt-3 border-t border-slate-200 dark:border-slate-700">
                                                    <select
                                                        value={member.role}
                                                        onChange={(e) => handleRoleChange(member.user_id, e.target.value)}
                                                        disabled={isLoading}
                                                        className="text-xs bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-600 rounded px-2 py-1 flex-1 text-slate-700 dark:text-slate-300"
                                                    >
                                                        <option value="researcher">연구원 (Researcher)</option>
                                                        <option value="student">학생 (Student)</option>
                                                        <option value="admin">관리자 승급 (Admin)</option>
                                                    </select>
                                                    <button
                                                        onClick={() => handleRemoveMember(member.user_id)}
                                                        disabled={isLoading}
                                                        className="text-xs px-3 py-1 bg-red-50 hover:bg-red-100 text-red-600 dark:bg-red-900/20 dark:hover:bg-red-900/40 dark:text-red-400 rounded transition-colors"
                                                    >
                                                        강퇴
                                                    </button>
                                                </div>
                                            )}
                                        </li>
                                    ))}
                                </ul>
                            )}
                            <div className="pt-2 sticky bottom-0 bg-white dark:bg-slate-900 pb-1 -mx-1 px-1 mt-2 border-t border-slate-100 dark:border-slate-800">
                                <button type="button" onClick={() => setView('menu')} className="w-full mt-2 py-2 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 rounded-lg font-medium hover:bg-slate-200 transition-colors">
                                    뒤로 가기
                                </button>
                            </div>
                        </div>
                    )}

                    {view === 'settings' && (
                        <form onSubmit={handleUpdateSettings} className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">연구실 이름</label>
                                <input
                                    type="text"
                                    value={settingsName}
                                    onChange={e => setSettingsName(e.target.value)}
                                    placeholder="연구실 이름"
                                    className="w-full px-3 py-2 border border-slate-300 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-800 focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 dark:text-slate-100"
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">입장 비밀번호</label>
                                <input
                                    type="text"
                                    value={settingsPassword}
                                    onChange={e => setSettingsPassword(e.target.value)}
                                    placeholder="비밀번호 없음 (빈칸 시 누구나 가입 가능)"
                                    className="w-full px-3 py-2 border border-slate-300 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-800 focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 dark:text-slate-100"
                                    autoComplete="off"
                                />
                                <p className="text-xs text-slate-500 mt-1">이전에 설정한 비밀번호가 표시되며, 수정하실 수 있습니다.</p>
                            </div>
                            <div className="flex gap-2 pt-4">
                                <button type="button" onClick={() => setView('menu')} className="flex-1 py-2 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 rounded-lg font-medium hover:bg-slate-200 transition-colors">
                                    취소
                                </button>
                                <button type="submit" disabled={isLoading || !settingsName.trim()} className="flex-1 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium transition-colors disabled:opacity-50 flex justify-center items-center">
                                    {isLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : '저장하기'}
                                </button>
                            </div>

                            <div className="mt-8 pt-6 border-t border-red-100 dark:border-red-900/30">
                                <h4 className="text-sm font-medium text-red-600 dark:text-red-400 mb-2">위험 구역 (Danger Zone)</h4>
                                <div className="p-4 bg-red-50 dark:bg-red-900/10 rounded-xl border border-red-100 dark:border-red-900/30 flex flex-col gap-3">
                                    <div className="text-sm text-red-700 dark:text-red-300">
                                        연구실을 삭제하면 모든 데이터(시약장, 시약 등) 복구가 불가능할 수 있습니다.
                                    </div>
                                    <button
                                        type="button"
                                        onClick={handleDeleteLab}
                                        disabled={isLoading}
                                        className="w-full py-2 bg-white dark:bg-slate-800 border border-red-200 dark:border-red-800 text-red-600 dark:text-red-400 rounded-lg font-medium hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors disabled:opacity-50"
                                    >
                                        연구실 완전 삭제
                                    </button>
                                </div>
                            </div>
                        </form>
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useEffect, useState } from 'react';
import { useTranslation } from 'react-i18next';
import type { Chemical, MsdsSection } from '../types';
import { fetchKoshaMsds } from '../services/koshaApi';
import { fetchPubChemMsds } from '../services/pubchemApi';
import { Loader2, X, FileText, ChevronDown, ChevronRight } from 'lucide-react';

interface MsdsModalProps {
    chemical: Chemical;
    isOpen: boolean;
    onClose: () => void;
}

export const MsdsModal: React.FC<MsdsModalProps> = ({ chemical, isOpen, onClose }) => {
    const { t, i18n } = useTranslation();
    const [loading, setLoading] = useState(true);
    const [sections, setSections] = useState<MsdsSection[]>([]);
    const [error, setError] = useState<string | null>(null);

    // Prevent body scroll when modal is open
    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
            loadMsdsData();
        } else {
            document.body.style.overflow = 'auto';
        }
        return () => {
            document.body.style.overflow = 'auto';
        };
    }, [isOpen, chemical]);

    const loadMsdsData = async () => {
        setLoading(true);
        setError(null);
        setSections([]);

        try {
            let data: MsdsSection[] = [];
            const isEnglish = i18n.language === 'en';

            if (isEnglish) {
                // English: PubChem (English) first, KOSHA fallback
                if (chemical.id) {
                    console.log('Fetching from PubChem (EN priority)...');
                    data = await fetchPubChemMsds(chemical.id);
                }
                if (data.length === 0 && chemical.koshaId) {
                    console.log('Fallback to KOSHA...');
                    data = await fetchKoshaMsds(chemical.koshaId);
                }
            } else {
                // Korean: KOSHA (Korean) first, PubChem fallback
                if (chemical.koshaId) {
                    console.log('Fetching from KOSHA (KO priority)...');
                    data = await fetchKoshaMsds(chemical.koshaId);
                }
                if (data.length === 0 && chemical.id) {
                    console.log('Fallback to PubChem...');
                    data = await fetchPubChemMsds(chemical.id);
                }
            }

            if (data.length === 0) {
                setError(t('msds_not_found'));
            } else {
                setSections(data);
            }
        } catch (err) {
            setError(t('msds_load_error'));
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-2xl w-full max-w-4xl h-[90vh] flex flex-col overflow-hidden border border-gray-100 dark:border-slate-800 animate-in zoom-in-95 duration-200">

                {/* Header */}
                <div className="p-5 border-b border-gray-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800 flex justify-between items-center shrink-0">
                    <div>
                        <h2 className="text-xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                            <FileText className="w-5 h-5 text-blue-600" />
                            {t('msds_title')}
                        </h2>
                        <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">
                            {chemical.name} {chemical.casNumber && `• CAS: ${chemical.casNumber}`}
                        </p>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-lg transition-colors"
                    >
                        <X className="w-6 h-6" />
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-6 bg-white dark:bg-slate-900">
                    {loading ? (
                        <div className="flex flex-col items-center justify-center h-full space-y-4">
                            <Loader2 className="w-10 h-10 text-blue-500 animate-spin" />
                            <p className="text-slate-500 animate-pulse">{t('msds_loading')}</p>
                        </div>
                    ) : error ? (
                        <div className="flex flex-col items-center justify-center h-full text-center p-6">
                            <div className="w-16 h-16 bg-gray-100 dark:bg-slate-800 rounded-full flex items-center justify-center mb-4">
                                <FileText className="w-8 h-8 text-gray-400" />
                            </div>
                            <h3 className="text-lg font-medium text-slate-900 dark:text-white mb-2">{error}</h3>
                            <button
                                onClick={loadMsdsData}
                                className="text-blue-600 hover:underline text-sm"
                            >
                                {t('msds_retry')}
                            </button>
                        </div>
                    ) : (
                        <div className="space-y-6">
                            {sections.map((section, idx) => (
                                <SectionItem key={idx} section={section} />
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

import { getPictogramUrl } from '../data/ghsCodes';

const SectionItem: React.FC<{ section: MsdsSection }> = ({ section }) => {
    const { t } = useTranslation();
    const [isExpanded, setIsExpanded] = useState(false);

    const renderValue = (label: string, value: string) => {
        // Detect Pictogram fields (KOSHA: "그림문자", PubChem: "Pictogram(s)")
        if (label === '그림문자' || label.toLowerCase().includes('pictogram')) {
            // Split by pipe (KOSHA) or newlines/commas
            const codes = value.split(/[|\n,]+/).map(s => s.trim()).filter(Boolean);

            // Map to URLs
            const images = codes.map(code => {
                const url = getPictogramUrl(code);
                return { code, url };
            }).filter(item => item.url);

            if (images.length > 0) {
                return (
                    <div className="flex flex-wrap gap-4 mt-1">
                        {images.map((img, idx) => (
                            <div key={idx} className="flex flex-col items-center group">
                                <div className="w-20 h-20 bg-white border border-gray-200 rounded-lg shadow-sm flex items-center justify-center p-2 transition-transform hover:scale-105">
                                    <img
                                        src={img.url}
                                        alt={img.code}
                                        className="w-full h-full object-contain"
                                    />
                                </div>
                                <span className="text-xs text-slate-400 mt-1">{img.code.replace(/\.(gif|jpg|png|svg)$/i, '')}</span>
                            </div>
                        ))}
                    </div>
                );
            }
        }
        // Handle pipe separators with newlines for better readability
        if (value && value.includes('|')) {
            return (
                <div className="flex flex-col gap-1">
                    {value.split('|').map((part, index) => (
                        <span key={index}>{part.trim()}</span>
                    ))}
                </div>
            );
        }

        return value || '-';
    };

    return (
        <div className="border border-gray-200 dark:border-slate-700 rounded-xl overflow-hidden shadow-sm">
            <button
