import React, { useState, useEffect } from 'react';
import { ShieldAlert, Check } from 'lucide-react';
import { useTranslation } from 'react-i18next';

export const SafetyDisclaimer: React.FC = () => {
    const [isOpen, setIsOpen] = useState(false);
    const [isClosing, setIsClosing] = useState(false);
    const { t, i18n } = useTranslation();

    useEffect(() => {
        const hasAcknowledged = localStorage.getItem('buril-safety-acknowledged');
        if (!hasAcknowledged) {
            setIsOpen(true);
        }
    }, []);

    const handleAcknowledge = () => {
        setIsClosing(true);
        setTimeout(() => {
            localStorage.setItem('buril-safety-acknowledged', 'true');
            setIsOpen(false);
        }, 300); // Wait for animation
    };

    if (!isOpen) return null;

    // Content defined here for simplicity instead of dictionary
    const content = i18n.language === 'ko' ? {
        points: [
            "본 서비스가 제공하는 폐액 분류 정보는 참고용이며, 실제 폐기 시에는 반드시 해당 시약의 MSDS(물질안전보건자료)와 소속 기관의 안전 규정을 최우선으로 따라야 합니다.",
            "제공된 결과에 따른 사고 및 손해에 대해 서비스 제공자는 법적 책임을 지지 않습니다.",
            "서로 다른 폐액을 혼합할 경우 폭발, 발열 등의 위험이 있으므로 혼합 전 적합성을 반드시 확인하십시오.",
            "불확실한 경우 반드시 연구실 안전관리자에게 문의하시기 바랍니다."
        ]
    } : {
        points: [
            "The disposal information provided is for reference only. Always prioritize the chemical's MSDS and your institution's safety regulations.",
            "The service provider is not liable for any accidents or damages resulting from the use of this information.",
            "Mixing different wastes can cause explosions or heat generation. Always verify compatibility before mixing.",
            "If uncertain, please consult your laboratory safety officer."
        ]
    };

    return (
        <div className={`fixed inset-0 z-[100] flex items-center justify-center p-5 bg-black/70 backdrop-blur-sm duration-300 ${isClosing ? 'animate-out fade-out opacity-0' : 'animate-in fade-in'}`}>
            <div className={`w-full max-w-[400px] bg-white dark:bg-slate-900 rounded-2xl shadow-2xl overflow-hidden p-6 duration-300 ${isClosing ? 'animate-out zoom-out-95 scale-95 opacity-0' : 'animate-in zoom-in-95'}`}>

                <div className="flex flex-col items-center text-center mb-6">
                    <div className="w-16 h-16 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center mb-4">
                        <ShieldAlert className="w-8 h-8 text-red-600 dark:text-red-500" />
                    </div>
                    <h2 className="text-xl font-bold text-slate-900 dark:text-white leading-tight">
                        {t('disclaimer_title')}
                    </h2>
                </div>

                <div className="bg-slate-50 dark:bg-slate-800 p-4 rounded-xl text-sm text-slate-600 dark:text-slate-300 mb-6 border border-slate-100 dark:border-slate-700 max-h-[300px] overflow-y-auto">
                    <ul className="list-disc pl-4 space-y-2">
                        {content.points.map((point, i) => (
                            <li key={i}>
                                {i === 0 || i === 2 ? <strong>{point}</strong> : point}
                            </li>
                        ))}
                    </ul>
                </div>

                <button
                    onClick={handleAcknowledge}
                    className="w-full py-3.5 px-4 bg-blue-600 hover:bg-blue-700 active:bg-blue-800 active:scale-95 text-white text-sm font-bold rounded-xl transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-200 dark:shadow-blue-900/20 break-keep leading-snug"
                >
                    <Check className="w-5 h-5 flex-shrink-0" />
                    {t('disclaimer_confirm')}
                </button>

            </div>
        </div>
    );
};

import React, { useState, useEffect, useCallback } from 'react';
import { fetchWasteLogs, deleteWasteLog } from '../services/wasteLogService';
import type { WasteLog } from '../types';
import { useTranslation } from 'react-i18next';
import { Trash2, ChevronDown, ChevronUp, FlaskConical, Loader2, AlertCircle, Search } from 'lucide-react';
import { CustomDialog } from './CustomDialog';
import { useLabStore } from '../store/useLabStore';
import type { WasteLogSortBy } from '../services/wasteLogService';

export const WasteLogView: React.FC = () => {
    const { t } = useTranslation();
    const currentLabId = useLabStore(state => state.currentLabId);
    const myLabs = useLabStore(state => state.myLabs);
    const currentRole = myLabs.find(m => m.lab_id === currentLabId)?.role;
    const canDeleteLogs = !currentLabId || currentRole === 'admin';
    const [logs, setLogs] = useState<WasteLog[]>([]);
    const [totalCount, setTotalCount] = useState(0);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [expandedId, setExpandedId] = useState<string | null>(null);
    const [page, setPage] = useState(0);
    const [deleteId, setDeleteId] = useState<string | null>(null);
    const [searchQuery, setSearchQuery] = useState('');
    const [searchInput, setSearchInput] = useState('');
    const [sortBy, setSortBy] = useState<WasteLogSortBy>('created_at');
    const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');
    const PAGE_SIZE = 20;

    const loadLogs = useCallback(async (reset: boolean = false) => {
        setIsLoading(true);
        setError(null);
        try {
            const offset = reset ? 0 : page * PAGE_SIZE;
            const result = await fetchWasteLogs(PAGE_SIZE, offset, {
                search: searchQuery || undefined,
                sortBy,
                sortOrder,
            });
            if (reset) {
                setLogs(result.logs);
                setPage(0);
            } else {
                setLogs(prev => [...prev, ...result.logs]);
            }
            setTotalCount(result.count);
        } catch {
            setError(t('dispose_error'));
        } finally {
            setIsLoading(false);
        }
    }, [page, searchQuery, sortBy, sortOrder, t]);

    // 실험실/검색/정렬 변경 시 재조회
    useEffect(() => {
        loadLogs(true);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentLabId, searchQuery, sortBy, sortOrder]);

    const handleSearchSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        setSearchQuery(searchInput.trim());
    };

    const handleLoadMore = () => {
        const nextPage = page + 1;
        setPage(nextPage);
        setIsLoading(true);
        setError(null);
        fetchWasteLogs(PAGE_SIZE, nextPage * PAGE_SIZE, {
            search: searchQuery || undefined,
            sortBy,
            sortOrder,
        })
            .then(result => {
                setLogs(prev => [...prev, ...result.logs]);
                setTotalCount(result.count);
            })
            .catch(() => setError(t('dispose_error')))
            .finally(() => setIsLoading(false));
    };

    // 시약명 포함 클라이언트 필터 (서버는 분류/처리자/메모만 검색)
    const filteredLogs = searchQuery
        ? logs.filter(log => {
            const q = searchQuery.toLowerCase();
            const matchText =
                log.disposal_category?.toLowerCase().includes(q) ||
                log.handler_name?.toLowerCase().includes(q) ||
                log.memo?.toLowerCase().includes(q);
            const matchChemical = log.chemicals?.some(
                c =>
                    c.chemical?.name?.toLowerCase().includes(q) ||
                    (c as any).name?.toLowerCase().includes(q) ||
                    (c as any).deleted_location?.toLowerCase().includes(q)
            );
            return matchText || matchChemical;
        })
        : logs;

    const handleDelete = async () => {
        if (!deleteId) return;
        if (!canDeleteLogs) {
            setError(t('log_delete_admin_only'));
            setDeleteId(null);
            return;
        }
        try {
            await deleteWasteLog(deleteId);
            setLogs(prev => prev.filter(l => l.id !== deleteId));
            setTotalCount(prev => prev - 1);
        } catch {
            setError(t('dispose_error'));
        } finally {
            setDeleteId(null);
        }
    };

    const formatDate = (dateStr: string) => {
        const d = new Date(dateStr);
        return d.toLocaleDateString(undefined, {
            year: 'numeric',
            month: 'short',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit',
        });
    };

    // Compute total volume from individual cart items
    const computeTotalVolume = (log: WasteLog): string | null => {
        if (log.total_volume_ml) return `${log.total_volume_ml} mL`;
        // Try summing individual volumes
        const total = log.chemicals.reduce((sum, c) => {
            if (c.volume) {
                const num = parseFloat(c.volume.replace(/[^0-9.]/g, ''));
                return sum + (isNaN(num) ? 0 : num);
            }
            return sum;
        }, 0);
        return total > 0 ? `${total} mL` : null;
    };

    const getPrimaryChemicalName = (log: WasteLog): string | null => {
        const first = log.chemicals?.[0] as any;
        return first?.chemical?.name || first?.name || null;
    };

    const getDeletedLocation = (log: WasteLog): string | null => {
        const first = log.chemicals?.[0] as any;
        if (first?.deleted_location) return String(first.deleted_location);

        const memo = log.memo || '';
        const match = memo.match(/삭제 위치:\s*([^|]+)/);
        return match?.[1]?.trim() || null;
    };

    const getDeleteReason = (log: WasteLog): string | null => {
        const memo = (log.memo || '').trim();
        if (!memo) return null;

        // 과거 데이터 호환: "사유 | 삭제 위치: ..." 형태에서 사유만 사용
        const reasonPart = memo.split('|')[0]?.trim() || '';
        const cleaned = reasonPart.replace(/^📝\s*/, '').trim();
        return cleaned || null;
    };

    return (
        <div className="p-5 flex flex-col gap-4" style={{ paddingBottom: '100px' }}>
            {/* Header */}
            <div className="flex items-center justify-between">
                <h2 className="text-xl font-bold text-slate-900 dark:text-white">
                    {t('log_title')}
                </h2>
                {totalCount > 0 && (
                    <span className="text-sm text-slate-500 dark:text-slate-400">
                        {totalCount}건
                    </span>
                )}
            </div>

            {/* 검색 & 정렬 */}
            <div className="flex items-center gap-2">
                <form onSubmit={handleSearchSubmit} className="relative flex-1 min-w-0">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <input
                        type="text"
                        value={searchInput}
                        onChange={e => setSearchInput(e.target.value)}
                        placeholder={t('log_search_placeholder')}
                        className="w-full h-[42px] pl-9 pr-4 py-2.5 text-sm bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-600 rounded-lg placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500/50"
                    />
                </form>
                <select
                    value={`${sortBy}-${sortOrder}`}
                    onChange={e => {
                        const [by, order] = e.target.value.split('-') as [WasteLogSortBy, 'asc' | 'desc'];
                        setSortBy(by);
                        setSortOrder(order);
                    }}
                    className="flex-shrink-0 h-[42px] py-2.5 px-3 text-sm bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500/50"
                >
                        <option value="created_at-desc">{t('log_sort_date_desc')}</option>
                        <option value="created_at-asc">{t('log_sort_date_asc')}</option>
                        <option value="disposal_category-asc">{t('log_sort_category_asc')}</option>
                        <option value="disposal_category-desc">{t('log_sort_category_desc')}</option>
                        <option value="handler_name-asc">{t('log_sort_handler_asc')}</option>
                        <option value="handler_name-desc">{t('log_sort_handler_desc')}</option>
                </select>
            </div>

            {/* Error */}
            {error && (
                <div className="flex items-center gap-2 text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-900/20 p-3 rounded-lg text-sm border border-red-100 dark:border-red-900/30">
                    <AlertCircle className="w-4 h-4" />
                    {error}
                </div>
            )}

            {/* Empty State */}
            {!isLoading && logs.length === 0 && !error && (
                <div className="text-center py-20">
                    <div className="inline-flex p-4 bg-slate-100 dark:bg-slate-800 rounded-full mb-4">
                        <FlaskConical className="w-8 h-8 text-slate-400 dark:text-slate-500" />
                    </div>
                    <p className="text-slate-500 dark:text-slate-400 text-sm">
                        {searchQuery ? t('log_search_empty') : t('log_empty')}
                    </p>
                </div>
            )}

            {/* Log Cards */}
            <div className="space-y-3">
                {filteredLogs.map(log => {
                    const isExpanded = expandedId === log.id;
                    const totalVol = computeTotalVolume(log);
                    const primaryChemicalName = getPrimaryChemicalName(log);
                    const deletedLocation = getDeletedLocation(log);
                    const deleteReason = getDeleteReason(log);
                    const locationBadgeClass = getLocationBadgeClass(deletedLocation);
                    const displayTitle = log.disposal_category.startsWith('기타')
                        ? (primaryChemicalName || log.disposal_category)
                        : log.disposal_category;

                    return (
                        <div
                            key={log.id}
                            className="bg-white dark:bg-slate-800 border border-gray-100 dark:border-slate-700 rounded-xl shadow-sm overflow-hidden transition-all"
                        >
                            {/* Card Header */}
                            <button
                                onClick={() => setExpandedId(isExpanded ? null : log.id)}
                                className="w-full p-4 text-left flex items-center gap-3 hover:bg-gray-50 dark:hover:bg-slate-750 transition-colors"
                            >
                                {/* Category Color Dot */}
                                <div className={`w-3 h-3 rounded-full flex-shrink-0 ${getCategoryColor(log.disposal_category)}`} />

                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center justify-between gap-2">
                                        <div className="flex items-center gap-2 min-w-0">
                                            <span className="font-semibold text-sm text-slate-800 dark:text-slate-200 truncate">
                                                {displayTitle}
                                            </span>
                                            {deletedLocation && (
                                                <span className={`text-[11px] px-1.5 py-0.5 rounded whitespace-nowrap ${locationBadgeClass}`}>
                                                    {deletedLocation}
                                                </span>
                                            )}
                                        </div>
                                        <span className="text-xs text-slate-400 dark:text-slate-500 whitespace-nowrap">
                                            {formatDate(log.created_at)}
                                        </span>
                                    </div>
                                    <div className="flex items-center gap-3 mt-1 text-xs text-slate-500 dark:text-slate-400">
                                        <span>{t('log_chemicals_count', { count: log.chemicals.length })}</span>
                                        {totalVol && <span>• {totalVol}</span>}
                                        {log.handler_name && <span>• {log.handler_name}</span>}
                                    </div>
                                </div>

                                {isExpanded
                                    ? <ChevronUp className="w-4 h-4 text-slate-400 flex-shrink-0" />
                                    : <ChevronDown className="w-4 h-4 text-slate-400 flex-shrink-0" />
                                }
                            </button>

                            {/* Expanded Detail */}
                            {isExpanded && (
                                <div className="px-4 pb-4 border-t border-gray-100 dark:border-slate-700">
                                    {/* Chemicals List */}
                                    <div className="space-y-2 mt-3">
                                        {log.chemicals.map((chem, idx) => (
                                            <div
                                                key={idx}
                                                className="flex justify-between items-center p-2.5 bg-gray-50 dark:bg-slate-750 rounded-lg text-sm"
                                            >
                                                <div>
                                                    <div className="font-medium text-slate-700 dark:text-slate-300">
                                                        {chem.chemical?.name || (chem as any).name || 'Unknown'}
                                                    </div>
                                                    <div className="text-xs text-slate-400 dark:text-slate-500 mt-0.5">
                                                        {chem.label && t(chem.label as any)}
                                                    </div>
                                                </div>
                                                {(chem.volume || chem.molarity) && (
                                                    <div className="text-xs text-slate-500 dark:text-slate-400 font-mono">
                                                        {chem.volume}{chem.volume && chem.molarity && ' • '}{chem.molarity}
                                                    </div>
                                                )}
                                            </div>
                                        ))}
                                    </div>

                                    {/* Disposal reason */}
                                    {deleteReason && (
                                        <div className="mt-3 p-2.5 bg-slate-50 dark:bg-slate-700/30 rounded-lg text-sm text-slate-700 dark:text-slate-300">
                                            <span className="font-medium">폐기 사유:</span> {deleteReason}
                                        </div>
                                    )}

                                    {/* Delete Button / Permission */}
                                    {canDeleteLogs ? (
                                        <button
                                            onClick={() => setDeleteId(log.id)}
                                            className="mt-3 w-full py-2 text-sm text-red-500 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors flex items-center justify-center gap-1.5"
                                        >
                                            <Trash2 className="w-3.5 h-3.5" />
                                            {t('log_delete') || '삭제'}
                                        </button>
                                    ) : (
                                        <div className="mt-3 text-xs text-slate-500 dark:text-slate-400 text-center py-2">
                                            {t('log_delete_admin_only')}
                                        </div>
                                    )}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>

            {/* Load More */}
            {logs.length < totalCount && (
                <button
                    onClick={handleLoadMore}
                    disabled={isLoading}
                    className="w-full py-3 text-sm text-blue-600 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-xl transition-colors font-medium"
                >
                    {isLoading
                        ? <Loader2 className="w-4 h-4 animate-spin mx-auto" />
                        : `더 보기 (${logs.length}/${totalCount})`
                    }
                </button>
            )}

            {/* Initial Loading */}
            {isLoading && logs.length === 0 && (
                <div className="flex justify-center py-10">
                    <Loader2 className="w-6 h-6 text-blue-500 animate-spin" />
                </div>
            )}

            <CustomDialog
                isOpen={canDeleteLogs && !!deleteId}
                onClose={() => setDeleteId(null)}
                title={t('log_delete') || '삭제'}
                description={t('log_delete_confirm')}
                type="confirm"
                isDestructive={true}
                onConfirm={handleDelete}
            />
        </div>
    );
};

/** Map disposal category label to a color dot */
function getCategoryColor(category: string): string {
    const lower = category.toLowerCase();
    if (lower.includes('할로겐') || lower.includes('halogen')) return 'bg-purple-500';
    if (lower.includes('유기') || lower.includes('organic')) return 'bg-orange-500';
    if (lower.includes('산') || lower.includes('acid')) return 'bg-red-500';
    if (lower.includes('알칼리') || lower.includes('alkali')) return 'bg-blue-500';
    if (lower.includes('주의') || lower.includes('warn')) return 'bg-yellow-500';
    return 'bg-gray-400';
}

function getLocationBadgeClass(location?: string | null): string {
    const lower = (location || '').toLowerCase();
    if (lower.includes('시약장') || lower.includes('cabinet')) {
        return 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300';
    }
    if (lower.includes('냉장고') || lower.includes('fridge')) {
        return 'bg-cyan-100 text-cyan-700 dark:bg-cyan-900/30 dark:text-cyan-300';
    }
    if (lower.includes('냉동') || lower.includes('freezer')) {
        return 'bg-indigo-100 text-indigo-700 dark:bg-indigo-900/30 dark:text-indigo-300';
    }
    if (lower.includes('후드') || lower.includes('hood')) {
        return 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300';
    }
    return 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-300';
}

import React, { useEffect, useState, useRef } from 'react';
import { Loader2, Plus, X, Beaker } from 'lucide-react';
import { cabinetService, type Cabinet } from '../../services/cabinetService';
import { useLabStore } from '../../store/useLabStore';
import { CabinetCard } from './components/CabinetCard';
import { CustomDialog } from '../../components/CustomDialog';
import { CabinetFormDialog } from './components/CabinetFormDialog';
import { CameraCaptureModal } from './components/CameraCaptureModal';
import { ImageActionMenu } from './components/ImageActionMenu';
import { ActivityLogModal } from './components/ActivityLogModal';
import { useTranslation } from 'react-i18next';

interface CabinetListViewProps {
    onSelectCabinet: (cabinetId: string) => void;
}

export function CabinetListView({ onSelectCabinet }: CabinetListViewProps) {
    const { t } = useTranslation();
    const [cabinets, setCabinets] = useState<Cabinet[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [isCreating, setIsCreating] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const { currentLabId, myLabs } = useLabStore();
    const currentRole = myLabs.find(m => m.lab_id === currentLabId)?.role;
    const canCreateCabinet = !currentLabId || currentRole === 'admin';

    // Dialog State
    const [dialogConfig, setDialogConfig] = useState<{
        isOpen: boolean;
        type: 'alert' | 'confirm' | 'prompt';
        title: string;
        description?: string;
        inputValue?: string;
        inputPlaceholder?: string;
        onConfirm?: (val?: string) => void;
        isDestructive?: boolean;
    }>({
        isOpen: false,
        type: 'alert',
        title: ''
    });

    const [formDialogConfig, setFormDialogConfig] = useState<{
        isOpen: boolean;
        mode: 'create' | 'edit';
        cabinetId?: string;
        initialName?: string;
        initialLocation?: string;
    }>({
        isOpen: false,
        mode: 'create'
    });

    const [imageMenu, setImageMenu] = useState<{ isOpen: boolean, cabinetId?: string }>({ isOpen: false });
    const [cameraModal, setCameraModal] = useState<{ isOpen: boolean, cabinetId?: string }>({ isOpen: false });
    const fileInputRef = useRef<HTMLInputElement>(null);

    const closeDialog = () => setDialogConfig(prev => ({ ...prev, isOpen: false }));
    const closeFormDialog = () => setFormDialogConfig(prev => ({ ...prev, isOpen: false }));
    const closeImageMenu = () => setImageMenu(prev => ({ ...prev, isOpen: false }));
    const closeCameraModal = () => setCameraModal(prev => ({ ...prev, isOpen: false }));

    // Inventory modal state
    const [inventoryModal, setInventoryModal] = useState<{
        isOpen: boolean;
        cabinetName: string;
        items: { name: string; shelfLevel: number; template: string; capacity?: string }[];
        isLoading: boolean;
    }>({ isOpen: false, cabinetName: '', items: [], isLoading: false });

    const handleInventory = async (e: React.MouseEvent, cabinet: Cabinet) => {
        e.stopPropagation();
        setInventoryModal({ isOpen: true, cabinetName: cabinet.name, items: [], isLoading: true });
        try {
            const { shelves } = await cabinetService.getCabinetDetails(cabinet.id);
            const items = shelves.flatMap(shelf =>
                shelf.items.map(item => ({
                    name: item.name,
                    shelfLevel: shelf.level,
                    template: item.template,
                    capacity: item.capacity
                }))
            );
            setInventoryModal(prev => ({ ...prev, items, isLoading: false }));
        } catch (err) {
            console.error('Failed to load inventory:', err);
            setInventoryModal(prev => ({ ...prev, isLoading: false }));
        }
    };

    // Disposal log modal state
    const [disposalLogModal, setDisposalLogModal] = useState<{
        isOpen: boolean;
        cabinetId: string;
        cabinetName: string;
    }>({ isOpen: false, cabinetId: '', cabinetName: '' });

    const handleDisposalLog = (e: React.MouseEvent, cabinet: Cabinet) => {
        e.stopPropagation();
        setDisposalLogModal({ isOpen: true, cabinetId: cabinet.id, cabinetName: cabinet.name });
    };

    const loadCabinets = async () => {
        try {
            setIsLoading(true);
            setError(null);
            const data = await cabinetService.getCabinets();
            setCabinets(data);
        } catch (err) {
            console.error(err);
            setError(t('cabinet_list_load_error'));
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        loadCabinets();
    }, [currentLabId]);

    const handleCreate = () => {
        setFormDialogConfig({
            isOpen: true,
            mode: 'create',
            initialName: '',
            initialLocation: ''
        });
    };

    const handleEdit = (e: React.MouseEvent, cabinet: Cabinet) => {
        e.stopPropagation();
        setFormDialogConfig({
            isOpen: true,
            mode: 'edit',
            cabinetId: cabinet.id,
            initialName: cabinet.name,
            initialLocation: cabinet.location || ''
        });
    };

    const handleFormConfirm = async (name: string, location?: string) => {
        try {
            setIsCreating(true);
            if (formDialogConfig.mode === 'create') {
                await cabinetService.createCabinet(name, location);
            } else if (formDialogConfig.mode === 'edit' && formDialogConfig.cabinetId) {
                await cabinetService.updateCabinet(formDialogConfig.cabinetId, { name, location });
            }
            closeFormDialog();
            await loadCabinets();
        } catch (err) {
            console.error('Save error:', err);
            setDialogConfig({
                isOpen: true,
                type: 'alert',
                title: t('cabinet_save_error_title'),
                description: t('cabinet_save_error_desc'),
                isDestructive: true
            });
        } finally {
            setIsCreating(false);
        }
    };

    const handleImageClick = (e: React.MouseEvent, cabinetId: string) => {
        e.stopPropagation();
        setImageMenu({ isOpen: true, cabinetId });
    };

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        const cabinetId = imageMenu.cabinetId;
        if (!file || !cabinetId) return;

        try {
            await cabinetService.uploadCabinetImage(cabinetId, file);
            await loadCabinets();
        } catch (err) {
            console.error('이미지 업로드 실패:', err);
            alert(t('cabinet_image_upload_error'));
        } finally {
            if (fileInputRef.current) fileInputRef.current.value = '';
        }
    };

    const handleCameraCapture = async (file: File) => {
        const cabinetId = cameraModal.cabinetId;
        if (!cabinetId) return;
        try {
            await cabinetService.uploadCabinetImage(cabinetId, file);
            await loadCabinets();
        } catch (err) {
            console.error('카메라 이미지 업로드 실패:', err);
            alert(t('cabinet_image_upload_error'));
        }
    };

    const handleDelete = (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        setDialogConfig({
            isOpen: true,
            type: 'confirm',
            title: t('cabinet_delete_title'),
            description: t('cabinet_delete_desc'),
            isDestructive: true,
            onConfirm: async () => {
                closeDialog();
                try {
                    await cabinetService.deleteCabinet(id);
                    await loadCabinets();
                } catch (err) {
                    console.error('Delete error:', err);
                    setDialogConfig({
                        isOpen: true,
                        type: 'alert',
                        title: t('cabinet_delete_error_title'),
                        description: t('cabinet_delete_error_desc'),
                        isDestructive: true
                    });
                }
            }
        });
    };

    if (isLoading) {
        return (
            <div className="h-full flex flex-col items-center justify-center p-6 gap-4">
                <Loader2 className="w-8 h-8 text-blue-500 animate-spin" />
                <p className="text-slate-500">{t('cabinet_loading')}</p>
            </div>
        );
    }

    return (
        <div className="h-full bg-slate-50 dark:bg-slate-950 overflow-y-auto p-5 pb-32">
            <div className="max-w-md mx-auto flex flex-col gap-6">
                <header className="flex justify-between items-center mt-4">
                    <div>
                        <h2 className="text-2xl font-bold text-slate-900 dark:text-slate-100">
                            {currentLabId ? `${myLabs.find(m => m.lab_id === currentLabId)?.lab?.name || t('cabinet_lab_fallback')}${t('cabinet_lab_suffix')}` : t('cabinet_my_cabinets')}
                        </h2>
                        <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">{t('cabinet_list_desc')}</p>
                    </div>
                </header>

                {error && (
                    <div className="p-4 bg-red-50 text-red-600 rounded-xl border border-red-100 text-sm">
                        {error}
                    </div>
                )}

                <div className="flex flex-col gap-4">
                    {cabinets.map(cabinet => (
                        <CabinetCard
                            key={cabinet.id}
                            cabinet={cabinet}
                            onClick={() => onSelectCabinet(cabinet.id)}
                            onEdit={canCreateCabinet ? (e) => handleEdit(e, cabinet) : undefined}
                            onDelete={canCreateCabinet ? (e) => handleDelete(e, cabinet.id) : undefined}
                            onImageClick={(e) => handleImageClick(e, cabinet.id)}
                            onInventory={(e) => handleInventory(e, cabinet)}
                            onDisposalLog={(e) => handleDisposalLog(e, cabinet)}
                        />
                    ))}

                    {cabinets.length === 0 && !error && (
                        <div className="text-center py-10 bg-white/50 dark:bg-slate-900/50 rounded-2xl border border-dashed border-slate-300 dark:border-slate-700">
                            <p className="text-slate-500 dark:text-slate-400">{t('cabinet_empty')}</p>
                        </div>
                    )}

                    {canCreateCabinet && (
                        <button
                            onClick={handleCreate}
                            disabled={isCreating}
                            className="w-full mt-2 py-4 px-6 bg-white dark:bg-slate-800 border-2 border-dashed border-blue-300 dark:border-blue-800/50 rounded-2xl text-blue-600 dark:text-blue-400 font-medium hover:bg-blue-50 dark:hover:bg-blue-900/20 hover:border-blue-400 transition-all flex items-center justify-center gap-2 group disabled:opacity-50"
                        >
                            {isCreating ? (
                                <Loader2 className="w-5 h-5 animate-spin" />
                            ) : (
                                <>
                                    <Plus className="w-5 h-5 group-hover:scale-110 transition-transform" />
                                    {t('cabinet_create_new')}
                                </>
                            )}
                        </button>
                    )}
                </div>
            </div>

            <CustomDialog
                isOpen={dialogConfig.isOpen}
                onClose={closeDialog}
                title={dialogConfig.title}
                description={dialogConfig.description}
                type={dialogConfig.type}
                inputValue={dialogConfig.inputValue}
                onInputChange={(val) => setDialogConfig(prev => ({ ...prev, inputValue: val }))}
                inputPlaceholder={dialogConfig.inputPlaceholder}
                isDestructive={dialogConfig.isDestructive}
                onConfirm={() => dialogConfig.onConfirm?.(dialogConfig.inputValue)}
            />

            <CabinetFormDialog
                isOpen={formDialogConfig.isOpen}
                onClose={closeFormDialog}
                title={formDialogConfig.mode === 'create' ? t('cabinet_create_title') : t('cabinet_edit_info_title')}
                description={formDialogConfig.mode === 'create' ? t('cabinet_create_desc') : undefined}
                initialName={formDialogConfig.initialName}
                initialLocation={formDialogConfig.initialLocation}
                onConfirm={handleFormConfirm}
                isLoading={isCreating}
            />

            <ImageActionMenu
                isOpen={imageMenu.isOpen}
                onClose={closeImageMenu}
                onSelectCamera={() => {
                    setCameraModal({ isOpen: true, cabinetId: imageMenu.cabinetId });
                }}
                onSelectGallery={() => {
                    fileInputRef.current?.click();
                }}
                hasImage={!!cabinets.find(c => c.id === imageMenu.cabinetId)?.image_url}
                onDeleteImage={async () => {
                    const cabinetId = imageMenu.cabinetId;
                    if (!cabinetId) return;
                    try {
                        await cabinetService.updateCabinet(cabinetId, { image_url: '' });
                        await loadCabinets();
                    } catch (err) {
                        console.error('이미지 삭제 실패:', err);
                    }
                }}
            />

            <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileChange}
                accept="image/*"
                className="hidden"
            />

            <CameraCaptureModal
                isOpen={cameraModal.isOpen}
                onClose={closeCameraModal}
                onCapture={handleCameraCapture}
            />

            <ActivityLogModal
                isOpen={disposalLogModal.isOpen}
                cabinetId={disposalLogModal.cabinetId}
                cabinetName={disposalLogModal.cabinetName}
                onClose={() => setDisposalLogModal(prev => ({ ...prev, isOpen: false }))}
            />

            {/* Inventory Modal */}
            {inventoryModal.isOpen && (
                <div className="fixed inset-0 z-[100] flex items-end justify-center animate-in fade-in duration-200">
                    <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setInventoryModal(prev => ({ ...prev, isOpen: false }))} />
                    <div className="relative bg-white dark:bg-slate-800 rounded-t-2xl shadow-xl w-full max-w-md max-h-[70vh] flex flex-col animate-in slide-in-from-bottom duration-300">
                        {/* Header */}
                        <div className="flex items-center justify-between p-4 border-b border-gray-100 dark:border-slate-700 shrink-0">
                            <div className="flex items-center gap-2">
                                <Beaker className="w-5 h-5 text-emerald-500" />
                                <span className="font-semibold text-slate-800 dark:text-slate-100">{inventoryModal.cabinetName} 재고 목록</span>
                            </div>
                            <button
                                onClick={() => setInventoryModal(prev => ({ ...prev, isOpen: false }))}
                                className="p-1 rounded-full text-gray-400 hover:bg-gray-200 dark:hover:bg-slate-700 hover:text-gray-600 transition-colors"
                            >
                                <X size={18} />
                            </button>
                        </div>
                        {/* Content */}
                        <div className="overflow-y-auto p-4 flex flex-col gap-3">
                            {inventoryModal.isLoading ? (
                                <div className="flex items-center justify-center py-8">
                                    <Loader2 className="w-6 h-6 text-blue-500 animate-spin" />
                                </div>
                            ) : inventoryModal.items.length === 0 ? (
                                <p className="text-center text-slate-400 dark:text-slate-500 py-8">시약이 없습니다.</p>
                            ) : (
                                (() => {
                                    // Group by shelf level
                                    const grouped = new Map<number, typeof inventoryModal.items>();
                                    for (const item of inventoryModal.items) {
                                        const list = grouped.get(item.shelfLevel) || [];
                                        list.push(item);
                                        grouped.set(item.shelfLevel, list);
                                    }
                                    const sortedLevels = [...grouped.keys()].sort((a, b) => a - b);
                                    return sortedLevels.map(level => (
                                        <div key={level}>
                                            <h4 className="text-xs font-semibold text-slate-500 dark:text-slate-400 mb-1.5">
                                                {`📦 ${level + 1}층 선반`}
                                            </h4>
                                            <div className="flex flex-col gap-1">
                                                {grouped.get(level)!.map((item, idx) => (
                                                    <div key={idx} className="flex items-center gap-2 px-3 py-2 bg-slate-50 dark:bg-slate-700/50 rounded-lg">
                                                        <span className="text-xs text-slate-400 dark:text-slate-500 font-mono w-5">{idx + 1}.</span>
                                                        <span className="text-sm text-slate-700 dark:text-slate-200 font-medium">{item.name}</span>
                                                        {item.capacity && (
                                                            <span className="text-xs text-slate-500 dark:text-slate-400 ml-auto bg-slate-200/50 dark:bg-slate-600/50 px-2 py-0.5 rounded-md">
                                                                {item.capacity}
                                                            </span>
                                                        )}
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    ));
                                })()
                            )}
                        </div>
                        {/* Footer */}
                        {!inventoryModal.isLoading && inventoryModal.items.length > 0 && (
                            <div className="p-3 border-t border-gray-100 dark:border-slate-700 text-center shrink-0">
                                <span className="text-xs text-slate-400 dark:text-slate-500">
                                    총 {inventoryModal.items.length}개 시약
                                </span>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

