import React, { Suspense, useEffect, useMemo, useRef, useState, useCallback } from 'react';
import * as THREE from 'three';
import { Canvas, useThree } from '@react-three/fiber';
import { OrbitControls, Environment, ContactShadows } from '@react-three/drei';
import { useFridgeStore } from '../../store/fridgeStore';
import { ShelfUnit } from './ShelfUnit';
import { CabinetFrame } from './CabinetFrame';
import { ResponsiveCamera } from './ResponsiveCamera';
import { Eye, EyeOff } from 'lucide-react';
import { useTranslation } from 'react-i18next';

/** OrbitControls target가 변경될 때 동기화 (prop만으로는 갱신이 안 될 수 있음) */
function SyncOrbitTarget({ target }: { target: [number, number, number] }) {
    const { controls } = useThree();
    useEffect(() => {
        const orbit = controls as { target: { set: (x: number, y: number, z: number) => void }; update?: () => void } | null;
        if (orbit?.target) orbit.target.set(...target);
        if (typeof orbit?.update === 'function') orbit.update();
    }, [controls, target]);
    return null;
}

/** CabinetFrame과 동일 */
const SHELF_BOTTOM_Y = -0.25;
/** 선반 두께 (ShelfUnit SHELF_HEIGHT와 동일) */
const SHELF_HEIGHT = 0.2;

/** 정면 위 약 30도 각도 - 시약 배치 시 고정 시점 */
const PLACE_ELEVATION_DEG = 30; // 수평선 기준 위 30도
const PLACE_ELEVATION_RAD = PLACE_ELEVATION_DEG * (Math.PI / 180);

function useCabinetCamera(
    cabinetWidth: number,
    cabinetHeight: number,
    mode: 'VIEW' | 'EDIT' | 'PLACE',
    aspect: number
) {

    return useMemo(() => {
        // FOV = 52. Math.tan(26 * PI/180) = 0.4877
        const fovFactor = 2 * Math.tan(26 * Math.PI / 180); // ~0.975

        // VIEW/EDIT/PLACE 모드 모두 하단 UI를 피하기 위해 화면 하단을 안전 영역으로 비워둠
        // 이전 45%에서 35%로 줄여서 캐비닛이 너무 위로 치우치지 않고 자연스럽게 위치하도록 조정
        const blockedRatio = 0.35;

        // 캐비닛 위아래 여유 공간 (줌아웃을 위해 여백 증가)
        const visibleHeightNeeded = cabinetHeight + 2.5;
        const totalVisibleHeight = visibleHeightNeeded / (1 - blockedRatio);

        // 화면 aspect(종횡비)를 고려하여 폭이 좁은 기기에서도 양옆이 잘리지 않도록 조정
        // 캐비닛 좌우 여유 공간 (줌아웃을 위해 여백 증가)
        const visibleWidthNeeded = cabinetWidth + 3.0;
        const distFromHeight = totalVisibleHeight / fovFactor;
        const distFromWidth = visibleWidthNeeded / (fovFactor * aspect);

        // 높이와 너비 중 더 먼 거리를 채택하여 전체가 다 보이도록 함
        const distance = Math.max(distFromHeight, distFromWidth);

        const minDistance = distance * 0.3;
        const maxDistance = distance * 2.5;

        // 캐비닛의 실제 중심 Y (바닥 기준값부터 높이 절반)
        // 카메라 전체 위치를 위로 올리기 위해 중심점을 임의로 더 높게 잡음 (예: + 1.0)
        const cabinetCenterY = SHELF_BOTTOM_Y + cabinetHeight / 2 + 1.2;

        // UI(35%)를 피해서 화면 상단 65% 영역의 중앙에 오도록 targetY 하향 조정
        const targetY = cabinetCenterY - (distance * fovFactor * blockedRatio / 2);
        const target: [number, number, number] = [0, targetY, 0];

        if (mode === 'PLACE') {
            // 배치 모드 초기 화면: 정면 위 30도에서 바라보는 고정 시점
            const posY = targetY + distance * Math.sin(PLACE_ELEVATION_RAD);
            const posZ = distance * Math.cos(PLACE_ELEVATION_RAD);
            return {
                position: [0, posY, posZ] as [number, number, number],
                minDistance,
                maxDistance,
                target,
                isPlaceMode: true,
                baseDistance: distance
            };
        }

        // VIEW / EDIT 모드: 약간 위(정면 5도)에서 내려다보아 전체적인 크기감이 자연스럽게 보이게 함
        // 기존 측면 오프셋 제거 및 정면 중심으로 배치
        const elevationRad = 5 * (Math.PI / 180);
        const posY = targetY + distance * Math.sin(elevationRad);
        const posZ = distance * Math.cos(elevationRad);

        return {
            position: [0, posY, posZ] as [number, number, number],
            minDistance,
            maxDistance,
            target,
            isPlaceMode: false,
            baseDistance: distance
        };
    }, [cabinetWidth, cabinetHeight, mode, aspect]);
}

export const FridgeScene: React.FC = () => {
    const { t } = useTranslation();
    // Canvas 컨테이너의 실제 크기로 aspect ratio 추적 (window 크기 대신)
    // → F12 개발자도구, 사이드바 등으로 뷰포트가 변해도 정확한 비율 유지
    const containerRef = useRef<HTMLDivElement>(null);
    const [containerAspect, setContainerAspect] = useState(() => {
        if (typeof window === 'undefined') return 0.6;
        return window.innerWidth / Math.max(1, window.innerHeight);
    });

    useEffect(() => {
        const el = containerRef.current;
        if (!el) return;
        const observer = new ResizeObserver((entries) => {
            for (const entry of entries) {
                const { width, height } = entry.contentRect;
                if (width > 0 && height > 0) {
                    setContainerAspect(width / height);
                }
            }
        });
        observer.observe(el);
        // 초기 측정
        const w = el.clientWidth;
        const h = el.clientHeight;
        if (w > 0 && h > 0) setContainerAspect(w / h);
        return () => observer.disconnect();
    }, []);

    const shelves = useFridgeStore((state) => state.shelves);
    const mode = useFridgeStore((state) => state.mode);
    const draggedItem = useFridgeStore((state) => state.draggedItem);
    const setDraggedItem = useFridgeStore((state) => state.setDraggedItem);

    useEffect(() => {
        if (!draggedItem) return;
        const onPointerUp = () => {
            setDraggedItem(null);
            document.body.style.cursor = 'default';
        };
        window.addEventListener('pointerup', onPointerUp);
        return () => window.removeEventListener('pointerup', onPointerUp);
    }, [draggedItem, setDraggedItem]);
    const cabinetWidth = useFridgeStore((state) => state.cabinetWidth);
    const cabinetHeight = useFridgeStore((state) => state.cabinetHeight);
    const cabinetDepth = useFridgeStore((state) => state.cabinetDepth);

    const floorShelf = useMemo(() => shelves.find(s => s.level === 0 || s.id === 'floor'), [shelves]);
    const floatingShelves = useMemo(() => shelves.filter(s => s.level !== 0 && s.id !== 'floor'), [shelves]);

    /** 상하 패널·선반 두께를 고려하여 N+1칸 균등 분할 */
    const { getShelfY, cellHeight } = useMemo(() => {
        const count = floatingShelves.length;
        const bottom = SHELF_BOTTOM_Y + 0.02; // Align perfectly with floorShelf position
        const top = SHELF_BOTTOM_Y + cabinetHeight; // 상판 하단 = 실제 천장 (PANEL 제외)
        const usableHeight = top - bottom;
        if (count === 0) return { getShelfY: () => 0, cellHeight: usableHeight };
        const totalGap = usableHeight - count * SHELF_HEIGHT;
        const gapHeight = totalGap / (count + 1);
        const getY = (index: number) => bottom + (index + 1) * (gapHeight + SHELF_HEIGHT);
        return { getShelfY: getY, cellHeight: gapHeight };
    }, [floatingShelves.length, cabinetHeight]);

    const cameraConfig = useCabinetCamera(cabinetWidth, cabinetHeight, mode, containerAspect);
    const [shelfFocusTarget, setShelfFocusTarget] = useState<[number, number, number] | null>(null);
    const focusedShelfId = useFridgeStore((state) => state.focusedShelfId);
    const setFocusedShelfId = useFridgeStore((state) => state.setFocusedShelfId);
    const GROUP_OFFSET_Y = -0.5;

    /** 탑뷰 (90° 위에서 보기) 상태 */
    const [isTopDownView, setIsTopDownView] = useState(false);

    const effectiveTarget = shelfFocusTarget ?? cameraConfig.target;
    const isPlaceMode = mode === 'PLACE';

    // 포커스된 선반의 Y 좌표 계산 (탑뷰에서 위의 선반 숨김 로직에 사용)
    const focusedShelfY = useMemo(() => {
        if (!focusedShelfId && !shelfFocusTarget) return null;
        if (shelfFocusTarget) return shelfFocusTarget[1] - GROUP_OFFSET_Y;
        // fallback: ID 기반 계산
        if (floorShelf && focusedShelfId === floorShelf.id) return SHELF_BOTTOM_Y + 0.02;
        const idx = floatingShelves.findIndex(s => s.id === focusedShelfId);
        if (idx !== -1) return getShelfY(idx);
        return null;
    }, [focusedShelfId, shelfFocusTarget, floorShelf, floatingShelves, getShelfY]);

    const handleShelfFocus = useCallback((shelfId: string, localY: number) => {
        if (mode === 'PLACE' && focusedShelfId === shelfId) {
            setShelfFocusTarget(null);
            setFocusedShelfId(null);
            setIsTopDownView(false);
        } else {
            // 다른 선반으로 포커스 변경 시 탑뷰 해제
            if (focusedShelfId !== shelfId) setIsTopDownView(false);
            setShelfFocusTarget([0, GROUP_OFFSET_Y + localY, 0]);
            if (mode === 'PLACE') setFocusedShelfId(shelfId);
        }
    }, [mode, focusedShelfId, setFocusedShelfId]);

    // Auto-focus when navigated from search, or after auto-placement in PLACE mode
    useEffect(() => {
        if (focusedShelfId && (mode === 'VIEW' || mode === 'PLACE')) {
            const shelfIndex = floatingShelves.findIndex(s => s.id === focusedShelfId);
            if (shelfIndex !== -1) {
                setShelfFocusTarget([0, GROUP_OFFSET_Y + getShelfY(shelfIndex), 0]);
            } else if (floorShelf && focusedShelfId === floorShelf.id) {
                setShelfFocusTarget([0, GROUP_OFFSET_Y + (SHELF_BOTTOM_Y + 0.02), 0]);
            }
        }
    }, [focusedShelfId, mode, floatingShelves, floorShelf, getShelfY]);

    // highlightedItemId is managed externally (App.tsx sets it, user interaction clears it)

    const effectiveCameraConfig = useMemo(() => {
        if (shelfFocusTarget != null) {
            const fovFactor = 2 * Math.tan(26 * Math.PI / 180);
            const aspect = containerAspect;

            // 부드러운 보정 배수: aspect가 높을수록(가로가 넓을수록) 약간 더 여유를 줌
            // 기존의 절벽(aspect>=1 → 2.0, <1 → 1.2)을 부드러운 보간으로 교체
            const t = Math.min(1, Math.max(0, (aspect - 0.5) / 1.5));
            const widthMultiplier = 1.1 + 0.3 * t;

            // === 탑뷰 모드: 카메라를 선반 위(80도 각도)에 배치 ===
            if (isTopDownView) {
                // 선반의 폭과 깊이가 모두 보이도록 거리 계산
                const visibleWidthNeeded = cabinetWidth + 1.5;
                const visibleDepthNeeded = cabinetDepth + 1.5;
                const distFromWidth = (visibleWidthNeeded / (fovFactor * aspect)) * widthMultiplier;
                const distFromDepth = (visibleDepthNeeded / fovFactor) * 1.2; // 깊이는 화면 세로 길이에 비례하므로 기본 보정만 적용
                const dist = Math.max(distFromWidth, distFromDepth);

                const targetY = shelfFocusTarget[1];

                const angleRad = 80 * Math.PI / 180;
                const posY = targetY + dist * Math.sin(angleRad);
                const posZ = dist * Math.cos(angleRad);

                // Y축(직교)으로만 위치를 낮추면 카메라가 대상물에 물리적으로 가까워져(줌인)버립니다.
                // 화면상에서만 위로 올리려면 카메라의 '시선 평면과 수평인 아래쪽'으로 패닝(Pan)해야 합니다.
                // 따라서 카메라가 바라보는 각도(80도)를 고려하여 Y와 Z 좌표를 동시에 조절합니다.
                const panOffset = dist * fovFactor * 0.15; // 화면 높이의 약 15%만큼 위로 이동
                const panY = -panOffset * Math.cos(angleRad); // 약간 아래로
                const panZ = panOffset * Math.sin(angleRad);  // 꽤 뒤로 물러남

                return {
                    ...cameraConfig,
                    position: [0, posY + panY, posZ + panZ] as [number, number, number],
                    target: [0, targetY + panY, panZ] as [number, number, number],
                };
            }

            // === 일반 선반 포커스 모드 ===
            const visibleWidthNeeded = cabinetWidth + 1.0;
            const distFromWidth = (visibleWidthNeeded / (fovFactor * aspect)) * widthMultiplier;

            let dist = isPlaceMode ? cameraConfig.baseDistance * 0.8 : cameraConfig.baseDistance * 0.6;
            dist = Math.max(dist, distFromWidth);

            const visibleHeight = dist * fovFactor;
            const yOffset = visibleHeight * 0.15;
            const targetY = shelfFocusTarget[1] - yOffset;

            const posY = targetY + dist * Math.sin(PLACE_ELEVATION_RAD);
            const posZ = dist * Math.cos(PLACE_ELEVATION_RAD);

            return {
                ...cameraConfig,
                position: [0, posY, posZ] as [number, number, number],
                target: [0, targetY, 0] as [number, number, number],
            };
        }
        return { ...cameraConfig, target: effectiveTarget };
    }, [shelfFocusTarget, effectiveTarget, cameraConfig, isPlaceMode, isTopDownView, cabinetWidth, cabinetDepth, containerAspect]);

    return (
        <div ref={containerRef} className="w-full bg-gray-100 relative" style={{ height: 'calc(100dvh - 7rem)' }}>
            <Canvas
                shadows="percentage"
                camera={{ position: cameraConfig.position, fov: 52 }}
                gl={{ preserveDrawingBuffer: true }}
            >
                <Suspense fallback={null}>
                    <ResponsiveCamera
                        cabinetWidth={cabinetWidth}
                        cabinetHeight={cabinetHeight}
                        config={effectiveCameraConfig}
                    />
                    <Environment preset="city" />
                    <ambientLight intensity={0.5} />
                    <spotLight position={[10, 10, 10]} angle={0.15} penumbra={1} shadow-mapSize={[512, 512]} castShadow />

                    <group position={[0, -0.5, 0]}>
                        <CabinetFrame
                            width={cabinetWidth}
                            depth={cabinetDepth}
                            cabinetHeight={cabinetHeight}
                            dimmed={isPlaceMode && focusedShelfId != null}
                            hideTop={isTopDownView}
                        />
                        {/* 바닥면 (floor shelf) */}
                        {floorShelf && (() => {
                            const floorY = SHELF_BOTTOM_Y + 0.02;
                            // 탑뷰 시 포커스된 선반 위의 선반은 숨김
                            const isAboveFocused = isTopDownView && focusedShelfY != null && floorY > focusedShelfY + 0.01;
                            if (isAboveFocused) return null;
                            return (
                                <ShelfUnit
                                    key={floorShelf.id}
                                    shelf={floorShelf}
                                    position={[0, floorY, 0]}
                                    shelfWidth={cabinetWidth}
                                    shelfDepth={cabinetDepth}
                                    cellHeight={cellHeight}
                                    onShelfFocus={(localY) => handleShelfFocus(floorShelf.id, localY)}
                                    shelfHeight={0.05}
                                    isDimmed={isPlaceMode && focusedShelfId != null && floorShelf.id !== focusedShelfId}
                                />
                            );
                        })()}

                        {/* 띄워진 선반들 */}
                        {floatingShelves.map((shelf, index) => {
                            const shelfY = getShelfY(index);
                            // 탑뷰 시 포커스된 선반 위의 선반은 숨김
                            const isAboveFocused = isTopDownView && focusedShelfY != null && shelfY > focusedShelfY + 0.01;
                            if (isAboveFocused) return null;
                            return (
                                <ShelfUnit
                                    key={shelf.id}
                                    shelf={shelf}
                                    position={[0, shelfY, 0]}
                                    shelfWidth={cabinetWidth}
                                    shelfDepth={cabinetDepth}
                                    cellHeight={cellHeight}
                                    onShelfFocus={(localY) => handleShelfFocus(shelf.id, localY)}
                                    isDimmed={isPlaceMode && focusedShelfId != null && shelf.id !== focusedShelfId}
                                />
                            );
                        })}

                    </group>

                    <ContactShadows position={[0, -1, 0]} opacity={0.4} scale={Math.max(10, cabinetWidth * 1.5)} blur={2.5} far={4} frames={1} />
                    <OrbitControls
                        makeDefault
                        minPolarAngle={isTopDownView ? 0 : Math.PI / 6}
                        maxPolarAngle={Math.PI / 2}
                        minDistance={cameraConfig.minDistance}
                        maxDistance={cameraConfig.maxDistance}
                        target={effectiveTarget}
                        enableRotate={!isPlaceMode && !draggedItem}
                        enablePan={!draggedItem}
                        enableZoom={true}
                        touches={{ ONE: THREE.TOUCH.ROTATE, TWO: THREE.TOUCH.DOLLY_PAN }}
                    />
                    <SyncOrbitTarget target={effectiveTarget} />
                </Suspense>
            </Canvas>

            {/* 탑뷰 토글 버튼 - 선반 포커스 시에만 표시 */}
            {shelfFocusTarget && (
                <button
                    onClick={() => setIsTopDownView(prev => !prev)}
                    className={`absolute top-16 right-4 z-20 flex items-center gap-1.5 px-3 py-2 rounded-full shadow-lg border text-xs font-medium transition-all ${isTopDownView
                        ? 'bg-blue-600 text-white border-blue-700 hover:bg-blue-700'
                        : 'bg-white/90 backdrop-blur text-gray-600 border-gray-200 hover:bg-blue-50 hover:text-blue-600 hover:border-blue-300'
                        }`}
                    title={t('topdown_view')}
                >
                    {isTopDownView ? <EyeOff size={16} /> : <Eye size={16} />}
                    <span>{t('topdown_view')}</span>
                </button>
            )}
        </div>
    );
};

import React, { useRef, useMemo, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import type { ThreeEvent } from '@react-three/fiber';
import type { ReagentPlacement } from '../../types/fridge';
import { useSpring, animated } from '@react-spring/three';
import { useFridgeStore } from '../../store/fridgeStore';
import * as THREE from 'three';

interface ReagentItemProps {
    item: ReagentPlacement;
    shelfWidth: number;
    shelfDepth?: number;
    isGhost?: boolean;
    isValid?: boolean;
    /** PLACE 모드에서 비선택 선반의 시약 비활성화 시각 처리 */
    dimmed?: boolean;
}

export const CONTAINER_BASE_WIDTHS: Record<string, number> = { A: 8, B: 10, C: 9, D: 15 };

// --- Shared Geometries (Performance Optimization) ---
// Type A: 갈색 병
const GEO_A_BODY = new THREE.CylinderGeometry(0.22, 0.24, 0.7, 10);
const GEO_A_NECK = new THREE.CylinderGeometry(0.1, 0.14, 0.18, 8);
const GEO_A_CAP = new THREE.CylinderGeometry(0.12, 0.12, 0.1, 8);
const GEO_A_BOTTOM = new THREE.CylinderGeometry(0.24, 0.24, 0.02, 10);

// Type B: 플라스틱 용기
const GEO_B_BODY = new THREE.BoxGeometry(0.5, 0.9, 0.35);
const GEO_B_CAP = new THREE.BoxGeometry(0.52, 0.1, 0.37);
const GEO_B_LABEL_FRONT = new THREE.PlaneGeometry(0.4, 0.55);
const GEO_B_LABEL_STRIP = new THREE.PlaneGeometry(0.38, 0.08);

// Type C: 솔벤트 캔
const GEO_C_BODY = new THREE.CylinderGeometry(0.35, 0.35, 1.1, 12);
const GEO_C_RIM = new THREE.CylinderGeometry(0.36, 0.36, 0.04, 12);
const GEO_C_HANDLE = new THREE.TorusGeometry(0.15, 0.025, 6, 10, Math.PI);
const GEO_C_SPOUT = new THREE.CylinderGeometry(0.05, 0.06, 0.1, 8);

// Type D: 바이알 박스
const GEO_D_BOX = new THREE.BoxGeometry(1.2, 0.5, 0.8);
const GEO_D_DIV_VERT = new THREE.BoxGeometry(0.02, 0.44, 0.74);
const GEO_D_DIV_HORZ = new THREE.BoxGeometry(1.14, 0.44, 0.02);
const GEO_D_RIM = new THREE.BoxGeometry(1.22, 0.02, 0.82);

export const ItemGeometry: React.FC<{ type: string; defaultColor: string; opacity?: number; scale?: number; isHighlighted?: boolean }> = ({ type, defaultColor, opacity = 1, scale = 1, isHighlighted = false }) => {

    const materialRef = useRef<THREE.MeshStandardMaterial>(null);
    const highlightColor = useMemo(() => new THREE.Color('#ffff00'), []);
    const baseColor = useMemo(() => new THREE.Color(defaultColor), [defaultColor]);

    useFrame((state) => {
        if (!materialRef.current) return;
        if (isHighlighted) {
            const t = state.clock.elapsedTime;
            // Sine wave between 0 and 0.8 intensity for smooth pulsing
            const intensity = (Math.sin(t * 8) + 1) * 0.4;
            materialRef.current.emissive = highlightColor;
            materialRef.current.emissiveIntensity = intensity;
            materialRef.current.color = highlightColor;
        } else {
            materialRef.current.emissiveIntensity = 0;
            materialRef.current.color = baseColor;
        }
    });

    const materialProps = {
        transparent: opacity < 1,
        opacity,
        roughness: 0.3,
        metalness: 0.1,
        color: defaultColor
    };

    switch (type) {
        case 'A': // 갈색 병: 원기둥 몸통 + 좁은 목 + 뚜껑
            return (
                <group scale={scale}>
                    {/* 몸통 (갈색 원기둥) - 메인 그림자 캐스터 */}
                    <mesh castShadow position={[0, 0.35, 0]} geometry={GEO_A_BODY}>
                        <meshStandardMaterial ref={materialRef} {...materialProps} />
                    </mesh>
                    {/* 목 (좁은 원기둥) */}
                    <mesh position={[0, 0.78, 0]} geometry={GEO_A_NECK}>
                        <meshStandardMaterial color="#6D4C41" roughness={0.4} metalness={0.1}
                            transparent={opacity < 1} opacity={opacity} />
                    </mesh>
                    {/* 뚜껑 (검정 원기둥) */}
                    <mesh position={[0, 0.92, 0]} geometry={GEO_A_CAP}>
                        <meshStandardMaterial color="#212121" roughness={0.6} metalness={0.2}
                            transparent={opacity < 1} opacity={opacity} />
                    </mesh>
                    {/* 바닥 */}
                    <mesh position={[0, 0.01, 0]} geometry={GEO_A_BOTTOM}>
                        <meshStandardMaterial color="#5D4037" roughness={0.5}
                            transparent={opacity < 1} opacity={opacity} />
                    </mesh>
                </group>
            );
        case 'B': // 플라스틱 용기: 박스 몸통 + 뚜껑 + 라벨
            return (
                <group scale={scale}>
                    {/* 몸통 (흰색 박스) - 메인 그림자 캐스터 */}
                    <mesh castShadow position={[0, 0.45, 0]} geometry={GEO_B_BODY}>
                        <meshStandardMaterial ref={materialRef} {...materialProps} roughness={0.8} />
                    </mesh>
                    {/* 뚜껑 (파란색) */}
                    <mesh position={[0, 0.95, 0]} geometry={GEO_B_CAP}>
                        <meshStandardMaterial color="#1565C0" roughness={0.7} metalness={0.05}
                            transparent={opacity < 1} opacity={opacity} />
                    </mesh>
                    {/* 앞면 라벨 (Plane) */}
                    <mesh position={[0, 0.45, 0.176]} geometry={GEO_B_LABEL_FRONT}>
                        <meshStandardMaterial color="#FFFFFF" roughness={1} metalness={0}
                            transparent opacity={opacity * 0.92}
                            polygonOffset polygonOffsetFactor={-1} />
                    </mesh>
                    {/* 라벨 색상 띠 */}
                    <mesh position={[0, 0.6, 0.177]} geometry={GEO_B_LABEL_STRIP}>
                        <meshStandardMaterial color="#E53935" roughness={1} metalness={0}
                            transparent opacity={opacity * 0.9}
                            polygonOffset polygonOffsetFactor={-2} />
                    </mesh>
                </group>
            );
        case 'C': // 솔벤트 캔: 원기둥 몸통 + 손잡이
            return (
                <group scale={scale}>
                    {/* 캔 몸통 (금속 원기둥) - 메인 그림자 캐스터 */}
                    <mesh castShadow position={[0, 0.55, 0]} geometry={GEO_C_BODY}>
                        <meshStandardMaterial ref={materialRef} {...materialProps} metalness={0.6} roughness={0.4} />
                    </mesh>
                    {/* 캔 상단 림 */}
                    <mesh position={[0, 1.1, 0]} geometry={GEO_C_RIM}>
                        <meshStandardMaterial color="#9E9E9E" metalness={0.8} roughness={0.3}
                            transparent={opacity < 1} opacity={opacity} />
                    </mesh>
                    {/* 캔 하단 림 */}
                    <mesh position={[0, 0.01, 0]} geometry={GEO_C_RIM}>
                        <meshStandardMaterial color="#9E9E9E" metalness={0.8} roughness={0.3}
                            transparent={opacity < 1} opacity={opacity} />
                    </mesh>
                    {/* 손잡이 (Torus) */}
                    <mesh position={[0, 1.2, 0]} rotation={[Math.PI / 2, 0, 0]} geometry={GEO_C_HANDLE}>
                        <meshStandardMaterial color="#757575" metalness={0.9} roughness={0.2}
                            transparent={opacity < 1} opacity={opacity} />
                    </mesh>
                    {/* 주둥이 */}
                    <mesh position={[0.15, 1.15, 0]} geometry={GEO_C_SPOUT}>
                        <meshStandardMaterial color="#BDBDBD" metalness={0.7} roughness={0.3}
                            transparent={opacity < 1} opacity={opacity} />
                    </mesh>
                </group>
            );
        case 'D': // 바이알 박스: 박스 + 칸막이
            return (
                <group scale={scale}>
                    {/* 외곽 박스 - 메인 그림자 캐스터 */}
                    <mesh castShadow position={[0, 0.25, 0]} geometry={GEO_D_BOX}>
                        <meshStandardMaterial ref={materialRef} {...materialProps} />
                    </mesh>
                    {/* 칸막이 1 */}
                    <mesh position={[-0.3, 0.26, 0]} geometry={GEO_D_DIV_VERT}>
                        <meshStandardMaterial color="#BDBDBD" roughness={0.7}
                            transparent opacity={opacity * 0.7} />
                    </mesh>
                    {/* 칸막이 2 */}
                    <mesh position={[0, 0.26, 0]} geometry={GEO_D_DIV_VERT}>
                        <meshStandardMaterial color="#BDBDBD" roughness={0.7}
                            transparent opacity={opacity * 0.7} />
                    </mesh>
                    {/* 칸막이 3 */}
                    <mesh position={[0.3, 0.26, 0]} geometry={GEO_D_DIV_VERT}>
                        <meshStandardMaterial color="#BDBDBD" roughness={0.7}
                            transparent opacity={opacity * 0.7} />
                    </mesh>
                    {/* 가로 칸막이 */}
                    <mesh position={[0, 0.26, 0]} geometry={GEO_D_DIV_HORZ}>
                        <meshStandardMaterial color="#BDBDBD" roughness={0.7}
                            transparent opacity={opacity * 0.7} />
                    </mesh>
                    {/* 상단 테두리 */}
                    <mesh position={[0, 0.505, 0]} geometry={GEO_D_RIM}>
                        <meshStandardMaterial color="#E0E0E0" roughness={0.5}
                            transparent={opacity < 1} opacity={opacity} />
                    </mesh>
                </group>
            );
        default:
            return null;
    }
};

export const ReagentItem: React.FC<ReagentItemProps> = ({ item, shelfWidth, shelfDepth = 2, isGhost, isValid = true, dimmed = false }) => {
    const setDraggedItem = useFridgeStore(s => s.setDraggedItem);
    const draggedItem = useFridgeStore(s => s.draggedItem);
    const highlightedItemId = useFridgeStore(s => s.highlightedItemId);
    const mode = useFridgeStore(s => s.mode);
    const isBeingDragged = draggedItem?.id === item.id;
    const isHighlighted = highlightedItemId === item.id;

    const setSelectedReagentId = useFridgeStore(s => s.setSelectedReagentId);
    const setHighlightedItemId = useFridgeStore(s => s.setHighlightedItemId);
    const clickStart = React.useRef(0);

    // Auto-clear highlight after 5 seconds
    useEffect(() => {
        if (!isHighlighted) return;
        const timer = setTimeout(() => {
            setHighlightedItemId(null);
        }, 5000);
        return () => clearTimeout(timer);
    }, [isHighlighted, setHighlightedItemId]);

    const handlePointerDown = (e: ThreeEvent<PointerEvent>) => {
        if (isGhost) return;
        e.stopPropagation();
        clickStart.current = Date.now();

        // VIEW mode: only allow click (no drag)
        if (mode === 'VIEW') return;

        setDraggedItem({ id: item.id, originalShelfId: item.shelfId, originalPosition: item.position, originalDepthPosition: item.depthPosition });

        // 시각적 피드백
        document.body.style.cursor = 'grabbing';
    };

    const handlePointerUp = (e: ThreeEvent<PointerEvent>) => {
        if (isGhost) return;

        // Click Detection
        const elapsed = Date.now() - clickStart.current;
        if (elapsed < 200) {
            e.stopPropagation();
            // If highlighted, clear highlight on click
            if (isHighlighted) {
                setHighlightedItemId(null);
            }
            setSelectedReagentId(item.id);
            // Clicked -> Clear drag immediately so it doesn't count as drag
            if (mode !== 'VIEW') setDraggedItem(null);
            document.body.style.cursor = 'default';
            return;
        }

        if (isBeingDragged) {
            e.stopPropagation();
            document.body.style.cursor = 'default';
            setDraggedItem(null);
        }
    };

    const handlePointerEnter = (e: ThreeEvent<PointerEvent>) => {
        if (isGhost) return;
        e.stopPropagation();
        if (mode !== 'VIEW') {
            document.body.style.cursor = 'grab';
        }
    };

    const handlePointerLeave = () => {
        if (isGhost) return;
        document.body.style.cursor = 'default';
    };

    const centerPct = item.position + item.width / 2;
    const x = (centerPct / 100) * shelfWidth - shelfWidth / 2;
    const depthPos = item.depthPosition ?? 50;
    const z = (depthPos / 100) * shelfDepth - shelfDepth / 2;

    const { position } = useSpring({
        position: [x, 0, z],
        config: { mass: 1, tension: 170, friction: 26 }
    });

    const CONTAINER_COLORS: Record<string, string> = { A: '#8D6E63', B: '#F5F5F5', C: '#78909C', D: '#D7CCC8' };
    const defaultColor = isGhost ? (isValid ? '#4ade80' : '#ef4444') : (CONTAINER_COLORS[item.template] || '#8D6E63');
    let opacity = isGhost ? 0.6 : isBeingDragged ? 0.4 : 1;
    if (dimmed) opacity *= 0.5;

    const scale = item.width / (CONTAINER_BASE_WIDTHS[item.template] || 10);

    return (
        <animated.group
            position={position as any /* eslint-disable-line @typescript-eslint/no-explicit-any */}
            onPointerDown={handlePointerDown}
            onPointerUp={handlePointerUp}
            onPointerEnter={handlePointerEnter}
            onPointerLeave={handlePointerLeave}
        >
            <animated.group>
                <ItemGeometry
                    type={item.template}
                    defaultColor={defaultColor}
                    opacity={opacity}
                    scale={scale}
                    isHighlighted={isHighlighted}
                />
            </animated.group>
            {/* Label could go here */}
        </animated.group>
    );
};

import { useEffect, useRef } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';

interface ResponsiveCameraProps {
    cabinetWidth: number;
    cabinetHeight: number;
    config: {
        position: [number, number, number];
        minDistance: number;
        maxDistance: number;
        target: [number, number, number];
    };
}

const LERP_FACTOR = 0.06;
const ARRIVAL_THRESHOLD = 0.05;

/** 시약장 크기 변경 시 OrbitControls 동기화, 부드러운 전환. 줌/팬 시 즉시 보간 중단 */
export function ResponsiveCamera({ config }: ResponsiveCameraProps) {
    const { camera, controls, gl } = useThree();
    const targetPos = useRef(new THREE.Vector3(...config.position));
    const targetLookAt = useRef(new THREE.Vector3(...config.target));
    const isAnimating = useRef(true);
    const lastConfigKey = useRef('');

    useEffect(() => {
        const key = `${config.position.join(',')}|${config.target.join(',')}`;
        if (lastConfigKey.current === key) return;
        lastConfigKey.current = key;

        targetPos.current.set(...config.position);
        targetLookAt.current.set(...config.target);
        isAnimating.current = true;
    }, [config.position[0], config.position[1], config.position[2], config.target[0], config.target[1], config.target[2]]);

    // 줌/팬 시 보간 즉시 중단 → OrbitControls가 제어
    useEffect(() => {
        const el = gl.domElement;
        const stopAnim = () => { isAnimating.current = false; };
        el.addEventListener('wheel', stopAnim, { passive: true });
        el.addEventListener('pointerdown', stopAnim);
        return () => {
            el.removeEventListener('wheel', stopAnim);
            el.removeEventListener('pointerdown', stopAnim);
        };
    }, [gl]);

    useFrame(() => {
        const orbit = controls as { target: THREE.Vector3; update?: () => void } | null;
        if (!orbit?.target) return;

        if (!isAnimating.current) return;

        camera.position.lerp(targetPos.current, LERP_FACTOR);
        orbit.target.lerp(targetLookAt.current, LERP_FACTOR);
        orbit.update?.();

        const posDist = camera.position.distanceTo(targetPos.current);
        const tgtDist = orbit.target.distanceTo(targetLookAt.current);
        if (posDist < ARRIVAL_THRESHOLD && tgtDist < ARRIVAL_THRESHOLD) {
            isAnimating.current = false;
        }
    });

    return null;
}

import React, { useRef, useState } from 'react';
import type { ThreeEvent } from '@react-three/fiber';
import type { ShelfData } from '../../types/fridge';
import { useFridgeStore } from '../../store/fridgeStore';
import { ReagentItem, ItemGeometry, CONTAINER_BASE_WIDTHS } from './ReagentItem';
import { Divider } from './Divider';
import { checkCompatibility } from '../../utils/compatibilityChecker';
import { Html } from '@react-three/drei';
import { useTranslation } from 'react-i18next';

interface ShelfUnitProps {
    shelf: ShelfData;
    position: [number, number, number];
    shelfWidth: number;
    shelfDepth: number;
    cellHeight: number;
    onShelfFocus?: (shelfLocalY: number) => void;
    shelfHeight?: number;
    /** PLACE 모드에서 비선택 선반 시각적 비활성화 */
    isDimmed?: boolean;
}

const DEFAULT_SHELF_HEIGHT = 0.2;

interface MinimalChemicalData {
    properties?: { ph?: number;[key: string]: unknown };
    ghs?: { hazardStatements?: string[];[key: string]: unknown };
    [key: string]: unknown;
}

export const ShelfUnit: React.FC<ShelfUnitProps> = ({
    shelf,
    position,
    shelfWidth,
    shelfDepth,
    cellHeight,
    onShelfFocus,
    shelfHeight = DEFAULT_SHELF_HEIGHT,
    isDimmed = false
}) => {
    const { t } = useTranslation();
    const { draggedTemplate, draggedItem, shelves, moveReagent, setDraggedTemplate, setDraggedItem, setPendingPlacement } = useFridgeStore();
    const [ghostPos, setGhostPos] = useState<number | null>(null);
    const [ghostDepthPos, setGhostDepthPos] = useState<number>(50);
    const [isValid, setIsValid] = useState(true);
    const [warning, setWarning] = useState<string | null>(null);

    // 드래그(회전) vs 클릭 구분을 위한 pointerdown 좌표 추적
    const pointerDownPos = useRef<{ x: number; y: number } | null>(null);
    const CLICK_THRESHOLD = 5; // px 이내면 클릭, 초과하면 드래그

    const draggedPlacement = draggedItem
        ? shelves.flatMap(s => s.items).find(i => i.id === draggedItem.id)
        : null;
    const isPlacedItemDrag = !!draggedItem && !!draggedPlacement;

    const handlePointerMove = (e: ThreeEvent<PointerEvent>) => {
        const dragWidth = draggedTemplate?.width ?? draggedPlacement?.width;
        if (!draggedTemplate && !isPlacedItemDrag) return;
        if (!dragWidth) return;
        e.stopPropagation();

        const localX = e.point.x - position[0];
        const localZ = e.point.z - position[2];
        let pct = ((localX + shelfWidth / 2) / shelfWidth) * 100;
        pct = pct - dragWidth / 2;
        if (pct < 0) pct = 0;
        if (pct + dragWidth > 100) pct = 100 - dragWidth;

        const depthPct = ((localZ + shelfDepth / 2) / shelfDepth) * 100;
        const depthClamped = Math.max(0, Math.min(100, depthPct));

        setGhostPos(pct);
        setGhostDepthPos(depthClamped);


        // Manual placement always allowed (no collision blocking)
        setIsValid(true);

        if (draggedTemplate?.chemicalData) {
            const neighbors = shelf.items.filter(i => {
                const dist = Math.min(
                    Math.abs(i.position - (pct + draggedTemplate.width)),
                    Math.abs((i.position + i.width) - pct)
                );
                return dist < 5; // 5% proximity threshold
            });

            checkCompatibility([
                {
                    chemical: draggedTemplate.chemicalData || {
                        name: draggedTemplate.name,
                        ghs: { hazardStatements: [] },
                        properties: { ph: 7 }
                    },
                    quantity: 1
                } as any, // eslint-disable-line @typescript-eslint/no-explicit-any
                ...neighbors.map(n => ({
                    chemical: {
                        name: n.name,
                        ghs: { hazardStatements: n.hCodes || [] },
                        properties: { ph: n.isAcidic ? 1 : (n.isBasic ? 14 : 7) }
                    },
                    quantity: 1
                } as any)) // eslint-disable-line @typescript-eslint/no-explicit-any
            ]);

            let warnMsg = null;
            // Iterate over neighbors logic... 
            // Simplification for prototype:
            // If we have `isAcidic` and neighbor is `isBasic`, trigger warning.
            // We don't have the full rule engine unless we store full data.
            // Let's implement a simple Acid-Base check here using the flags.
            const chem = draggedTemplate.chemicalData as MinimalChemicalData | undefined;
            const isAcid = (chem?.properties?.ph ?? 7) < 7;
            const isBase = (chem?.properties?.ph ?? 7) > 10;
            // Also check hCodes if available?
            for (const n of neighbors) {
                if (isAcid && n.isBasic) warnMsg = t('compat_acid_base');
                if (isBase && n.isAcidic) warnMsg = t('compat_acid_base');
            }
            setWarning(warnMsg);
        } else {
            setWarning(null);
        }
    };

    const handlePointerLeave = () => {
        setGhostPos(null);
        setWarning(null);
        document.body.style.cursor = 'default';
    };

    const handlePointerEnter = () => {
        if (!draggedTemplate && !draggedItem) document.body.style.cursor = 'pointer';
    };

    const handlePointerDown = (e: ThreeEvent<PointerEvent>) => {
        pointerDownPos.current = { x: e.nativeEvent.clientX, y: e.nativeEvent.clientY };
    };

    const handlePointerUp = (e: ThreeEvent<PointerEvent>) => {
        const down = pointerDownPos.current;
        pointerDownPos.current = null;

        // 드래그(회전) 후 pointerup인 경우 → 클릭으로 처리하지 않음
        const isDrag = !down || Math.hypot(
            e.nativeEvent.clientX - down.x,
            e.nativeEvent.clientY - down.y
        ) > CLICK_THRESHOLD;

        if (!draggedTemplate && !draggedItem) {
            if (isDrag) return;
            e.stopPropagation();
            onShelfFocus?.(position[1]);
            return;
        }

        // 시약 선택 상태에서도, 호버 없이 선반만 클릭한 경우 포커스 처리
        if (ghostPos === null) {
            if (isDrag) return;
            e.stopPropagation();
            onShelfFocus?.(position[1]);
            return;
        }
        e.stopPropagation();

        if (isPlacedItemDrag && draggedItem) {
            moveReagent(draggedItem.id, shelf.id, ghostPos, ghostDepthPos);
            setDraggedItem(null);
            setGhostPos(null);
            document.body.style.cursor = 'default';
            return;
        }

        if (!draggedTemplate) return;

        const chem = draggedTemplate.chemicalData as any;

        // Instead of immediate placement, set pending placement to show the modal
        setPendingPlacement({
            shelfId: shelf.id,
            position: ghostPos,
            depthPosition: ghostDepthPos,
            width: draggedTemplate.width,
            template: draggedTemplate.type,
            chemicalData: chem
        });

        setDraggedTemplate(null);
        setGhostPos(null);
        document.body.style.cursor = 'default';
    };

    const shelfColor = ghostPos !== null ? '#f8f6f3' : '#e8e6e1';
    const shelfOpacity = isDimmed ? 0.35 : 1;

    return (
        <group position={position}>
            {/* Shelf Base - Drop Target */}
            <mesh
                receiveShadow
                position={[0, -shelfHeight / 2, 0]}
                onPointerDown={handlePointerDown}
                onPointerMove={handlePointerMove}
                onPointerEnter={handlePointerEnter}
                onPointerLeave={handlePointerLeave}
                onPointerUp={handlePointerUp}
            >
                <boxGeometry args={[shelfWidth, shelfHeight, shelfDepth]} />
                <meshStandardMaterial key={isDimmed ? 'dimmed' : 'normal'} color={shelfColor} transparent opacity={shelfOpacity} depthWrite={!isDimmed} />
            </mesh>

            {/* Items */}
            {shelf.items.map((item) => (
                <ReagentItem
                    key={item.id}
                    item={item}
                    shelfWidth={shelfWidth}
                    shelfDepth={shelfDepth}
                    dimmed={isDimmed}
                />
            ))}

            {/* Ghost Item - 새 시약 배치 또는 기존 시약 이동 */}
            {((draggedTemplate || isPlacedItemDrag) && ghostPos !== null) && (
                <group
                    position={[
                        ((ghostPos + (draggedTemplate?.width ?? draggedPlacement!.width) / 2) / 100) * shelfWidth - shelfWidth / 2,
                        0,
                        (ghostDepthPos / 100) * shelfDepth - shelfDepth / 2
                    ]}
                    onPointerUp={handlePointerUp}
                >
                    <ItemGeometry
                        type={(draggedTemplate?.type ?? draggedPlacement!.template) as string}
                        defaultColor={isValid ? (warning ? '#fbbf24' : '#4ade80') : '#ef4444'}
                        opacity={0.6}
                        scale={(draggedTemplate?.width ?? draggedPlacement!.width) / (CONTAINER_BASE_WIDTHS[draggedTemplate?.type ?? draggedPlacement!.template] || 10)}
                    />
                    {warning && (
                        <Html position={[0, 1.5, 0]} center>
                            <div className="bg-red-500 text-white text-xs px-2 py-1 rounded shadow whitespace-nowrap animate-pulse">
                                ⚠️ {warning}
                            </div>
                        </Html>
                    )}
                </group>
            )}

            {/* Dividers */}
            {shelf.dividers.map((pos, index) => (
                <Divider
                    key={`${shelf.id}-div-${index}`}
                    position={pos}
                    shelfWidth={shelfWidth}
                    shelfDepth={shelfDepth}
                    height={cellHeight}
                    dimmed={isDimmed}
                />
            ))}
        </group>
    );
};

import { useState, useEffect } from 'react';
import { X, History, Loader2, User, PackagePlus, Trash2, AlertTriangle } from 'lucide-react';
import { cabinetService, type ActivityLog, type ActivityActionType } from '../../../services/cabinetService';
import { useTranslation } from 'react-i18next';

interface ActivityLogModalProps {
    isOpen: boolean;
    cabinetId: string;
    cabinetName: string;
    onClose: () => void;
}

const REASON_LABELS: Record<string, string> = {
    used: 'cabinet_dispose_reason_used',
    expired: 'cabinet_dispose_reason_expired',
    broken: 'cabinet_dispose_reason_broken',
    other: 'cabinet_dispose_reason_other',
};

type FilterType = 'all' | 'add' | 'remove' | 'clear_all';

export function ActivityLogModal({ isOpen, cabinetId, cabinetName, onClose }: ActivityLogModalProps) {
    const { t } = useTranslation();
    const [logs, setLogs] = useState<ActivityLog[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [filter, setFilter] = useState<FilterType>('all');

    useEffect(() => {
        if (isOpen && cabinetId) {
            setIsLoading(true);
            cabinetService.getActivityLogs(cabinetId)
                .then(data => setLogs(data))
                .catch(err => console.error('Failed to load activity logs:', err))
                .finally(() => setIsLoading(false));
        }
    }, [isOpen, cabinetId]);

    if (!isOpen) return null;

    const filteredLogs = filter === 'all' ? logs : logs.filter(l => l.action_type === filter);

    const formatDate = (dateStr: string) => {
        const date = new Date(dateStr);
        return date.toLocaleString('ko-KR', {
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
            hour: '2-digit',
            minute: '2-digit',
        });
    };

    const getReasonLabel = (reason?: string) => {
        if (!reason) return null;
        const key = REASON_LABELS[reason];
        return key ? t(key) : reason;
    };

    const getActionConfig = (action: ActivityActionType) => {
        switch (action) {
            case 'add':
                return {
                    icon: <PackagePlus size={14} className="text-emerald-600" />,
                    label: t('activity_log_action_add'),
                    chipStyle: 'bg-emerald-100 text-emerald-700',
                    rowStyle: 'border-l-2 border-emerald-400',
                };
            case 'remove':
                return {
                    icon: <Trash2 size={14} className="text-red-500" />,
                    label: t('activity_log_action_remove'),
                    chipStyle: 'bg-red-100 text-red-700',
                    rowStyle: 'border-l-2 border-red-400',
                };
            case 'clear_all':
                return {
                    icon: <AlertTriangle size={14} className="text-orange-500" />,
                    label: t('activity_log_action_clear_all'),
                    chipStyle: 'bg-orange-100 text-orange-700',
                    rowStyle: 'border-l-2 border-orange-400',
                };
        }
    };

    const FILTERS: { key: FilterType; label: string }[] = [
        { key: 'all', label: t('activity_log_filter_all') },
        { key: 'add', label: t('activity_log_action_add') },
        { key: 'remove', label: t('activity_log_action_remove') },
        { key: 'clear_all', label: t('activity_log_action_clear_all') },
    ];

    return (
        <div className="fixed inset-0 z-[100] flex items-end justify-center animate-in fade-in duration-200">
            <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={onClose} />
            <div className="relative bg-white dark:bg-slate-800 rounded-t-2xl shadow-xl w-full max-w-md max-h-[80vh] flex flex-col animate-in slide-in-from-bottom duration-300">
                {/* Header */}
                <div className="flex items-center justify-between p-4 border-b border-gray-100 dark:border-slate-700 shrink-0">
                    <div className="flex items-center gap-2">
                        <History className="w-5 h-5 text-blue-500" />
                        <div>
                            <span className="font-semibold text-slate-800 dark:text-slate-100 text-sm">
                                {cabinetName}
                            </span>
                            <p className="text-xs text-slate-400 dark:text-slate-500">
                                {t('activity_log_title')}
                            </p>
                        </div>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-1 rounded-full text-gray-400 hover:bg-gray-200 dark:hover:bg-slate-700 hover:text-gray-600 transition-colors"
                    >
                        <X size={18} />
                    </button>
                </div>

                {/* Filter Tabs */}
                <div className="flex gap-1 px-4 pt-3 pb-2 shrink-0 overflow-x-auto">
                    {FILTERS.map(f => (
                        <button
                            key={f.key}
                            onClick={() => setFilter(f.key)}
                            className={`px-3 py-1 rounded-full text-xs font-medium whitespace-nowrap transition-colors ${filter === f.key
                                    ? 'bg-blue-600 text-white'
                                    : 'bg-gray-100 dark:bg-slate-700 text-gray-600 dark:text-slate-300 hover:bg-gray-200 dark:hover:bg-slate-600'
                                }`}
                        >
                            {f.label}
                        </button>
                    ))}
                </div>

                {/* Content */}
                <div className="overflow-y-auto px-4 pb-4 flex flex-col gap-2 flex-1">
                    {isLoading ? (
                        <div className="flex items-center justify-center py-8">
                            <Loader2 className="w-6 h-6 text-blue-500 animate-spin" />
                        </div>
                    ) : filteredLogs.length === 0 ? (
                        <p className="text-center text-slate-400 dark:text-slate-500 py-8 text-sm">
                            {t('activity_log_empty')}
                        </p>
                    ) : (
                        filteredLogs.map(log => {
                            const config = getActionConfig(log.action_type);
                            const reasonLabel = getReasonLabel(log.reason);
                            const displayName = log.performed_by_nickname || log.performed_by_email;
                            return (
                                <div
                                    key={log.id}
                                    className={`flex items-start gap-3 px-3 py-2.5 bg-slate-50 dark:bg-slate-700/50 rounded-lg pl-4 ${config.rowStyle}`}
                                >
                                    <div className="flex-1 min-w-0">
                                        {/* Action type + Item name */}
                                        <div className="flex items-center gap-1.5 flex-wrap">
                                            <span className={`inline-flex items-center gap-1 text-[10px] font-semibold px-1.5 py-0.5 rounded-md shrink-0 ${config.chipStyle}`}>
                                                {config.icon}
                                                {config.label}
                                            </span>
                                            <span className="text-sm font-medium text-slate-700 dark:text-slate-200 truncate">
                                                {/* clear_all은 여러 이름이 나열될 수 있어서 줄임 */}
                                                {log.action_type === 'clear_all'
                                                    ? (log.item_name.length > 60 ? log.item_name.slice(0, 57) + '...' : log.item_name)
                                                    : log.item_name
                                                }
                                            </span>
                                        </div>

                                        {/* Reason badge (삭제 사유) */}
                                        {reasonLabel && (
                                            <span className="inline-block mt-1 text-[10px] text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-600 px-1.5 py-0.5 rounded">
                                                {reasonLabel}
                                            </span>
                                        )}

                                        {/* Memo */}
                                        {log.memo && (
                                            <p className="text-xs text-slate-400 dark:text-slate-500 mt-0.5 truncate">
                                                {log.memo}
                                            </p>
                                        )}

                                        {/* Performed by */}
                                        {displayName && (
                                            <div className="flex items-center gap-1 mt-1 text-xs text-slate-400 dark:text-slate-500">
                                                <User size={10} className="shrink-0" />
                                                <span className="truncate">{displayName}</span>
                                            </div>
                                        )}
                                    </div>

                                    {/* Date */}
                                    <span className="text-[10px] text-slate-400 dark:text-slate-500 shrink-0 mt-0.5">
                                        {formatDate(log.performed_at)}
                                    </span>
                                </div>
                            );
                        })
                    )}
                </div>

                {/* Footer */}
                {!isLoading && filteredLogs.length > 0 && (
                    <div className="p-3 border-t border-gray-100 dark:border-slate-700 text-center shrink-0">
                        <span className="text-xs text-slate-400 dark:text-slate-500">
                            {t('activity_log_count', { count: filteredLogs.length })}
                        </span>
                    </div>
                )}
            </div>
        </div>
    );
}

