                    </button>
                </div>

                {/* Content */}
                <div className="overflow-y-auto p-4 flex flex-col gap-2">
                    {isLoading ? (
                        <div className="flex items-center justify-center py-8">
                            <Loader2 className="w-6 h-6 text-blue-500 animate-spin" />
