import axios from 'axios';
import { XMLParser } from 'fast-xml-parser';


const BASE_URL = '/api/kosha';
const SERVICE_KEY = import.meta.env.VITE_KOSHA_API_KEY;

// KOSHA API Types (Internal)
import type { MsdsSection } from '../types';
// Reference: Image 4 (getChemList response) - Actual response has chemNameKor
interface KoshaSearchItem {
    chemId: number;
    chemNameKor: string;
    casNo: string;
    enNo?: string;
    keNo?: string;
    unNo?: string;
}

// XML Parser Instance
const parser = new XMLParser({
    ignoreAttributes: false,
    attributeNamePrefix: "@_"
});

/**
 * Fetches Physicochemical properties (specifically pH) from KOSHA API
 * Endpoint: /chemdetail09 (Physical/Chemical Properties)
 */
export const fetchKoshaPH = async (chemId: number | string): Promise<number | undefined> => {
    try {
        // KOSHA API requires 6-digit chemId string (e.g. "001034")
        const paddedId = String(chemId).padStart(6, '0');
        console.log(`[KOSHA] Fetching PH for chemId: ${paddedId} (Original: ${chemId})`);

        const res = await axios.get(`${BASE_URL}/chemdetail09`, {
            params: {
                chemId: paddedId,
                serviceKey: SERVICE_KEY
            }
        });

        const data = parser.parse(res.data);
        const items = data?.response?.body?.items?.item;

        if (!items) {
            console.warn('[KOSHA] No items returned for physicochemical properties.');
            return undefined;
        }

        // XML parser might return single object if only one item, or array
        const list = Array.isArray(items) ? items : [items];

        console.log('[KOSHA] Physicochemical Items:', list);

        // Find the item corresponding to pH
        // Based on doc: msdsItemNameKor could be "라.pH" or similar.
        const phItem = list.find((item: any) =>
            item.msdsItemNameKor && item.msdsItemNameKor.includes('pH')
        );

        if (phItem) {
            console.log(`[KOSHA] Found pH Item:`, phItem);

            if (phItem.itemDetail) {
                // Parse pH from string like "3.5 (at 20C)" or "7"
                // Simple regex to grab the first float number
                const match = String(phItem.itemDetail).match(/(-?[\d.]+)/);
                if (match) {
                    const val = parseFloat(match[1]);
                    console.log(`[KOSHA] Successfully parsed pH: ${val} from "${phItem.itemDetail}"`);
                    return val;
                } else {
                    console.warn(`[KOSHA] Failed to regex match pH from details: "${phItem.itemDetail}"`);
                }
            } else {
                console.warn('[KOSHA] pH item found but has no details.');
            }
        } else {
            console.warn('[KOSHA] pH item NOT found in list.');
        }

        return undefined;

    } catch (e) {
        console.warn('[KOSHA] Failed to fetch PH:', e);
        return undefined;
    }
};

/**
 * Resolves a Korean chemical name to CAS No and English Name using KOSHA MSDS API.
 * Does NOT fetch details anymore, as we relay to PubChem.
 */
export const resolveKoreanChemical = async (keyword: string): Promise<{ casNo: string, nameKo: string, nameEn: string, chemId: number } | null> => {
    try {
        console.log(`[KOSHA] Resolving: ${keyword}`);

        // 1. Search for Chemical
        const searchRes = await axios.get(`${BASE_URL}/chemlist`, {
            params: {
                searchWrd: keyword,
                searchCnd: 0, // 0 = Korean Name
                serviceKey: SERVICE_KEY
            }
        });

        const searchObj = parser.parse(searchRes.data);
        const items = searchObj?.response?.body?.items?.item;

        if (!items) {
            console.warn('[KOSHA] No results found.');
            return null;
        }

        // Handle single item vs array logic from XML parser
        const firstMatch: KoshaSearchItem = Array.isArray(items) ? items[0] : items;

        // Debugging: Log the structure to see correct keys
        console.log('[KOSHA] First Match:', firstMatch);

        const { chemId, chemNameKor, casNo } = firstMatch;

        if (!chemId || !casNo) return null;

        console.log(`[KOSHA] Resolved: ${chemNameKor} -> CAS: ${casNo}`);

        return {
            casNo: String(casNo).trim(),
            nameKo: chemNameKor || '', // Ensure valid string
            nameEn: '', // KOSHA chemlist does not return English Name. We rely on PubChem for that.
            chemId: Number(chemId)
        };

    } catch (error) {
        console.error('[KOSHA] API Error:', error);
        return null;
    }
};

/**
 * Resolves a CAS No to KOSHA chemId
 */
export const resolveCasChemical = async (casNo: string): Promise<{ chemId: number; nameKo?: string } | null> => {
    try {
        console.log(`[KOSHA] Resolving CAS: ${casNo}`);

        // Search for Chemical by CAS
        const searchRes = await axios.get(`${BASE_URL}/chemlist`, {
            params: {
                searchWrd: casNo,
                searchCnd: 1, // 1 = CAS No (Confirmed by doc)
                serviceKey: SERVICE_KEY
            }
        });

        const searchObj = parser.parse(searchRes.data);
        const items = searchObj?.response?.body?.items?.item;

        if (!items) {
            console.warn('[KOSHA] No results found for CAS.');
            return null;
        }

        const firstMatch: KoshaSearchItem = Array.isArray(items) ? items[0] : items;
        const { chemId, chemNameKor } = firstMatch;

        if (!chemId) return null;

        console.log(`[KOSHA] CAS Resolved: ${casNo} -> chemId: ${chemId}, name: ${chemNameKor}`);
        return { chemId: Number(chemId), nameKo: chemNameKor || undefined };

    } catch (error) {
        console.error('[KOSHA] CAS Resolve Error:', error);
        return null;
    }
};

// --- MSDS Full Fetching ---

/**
 * Fetches all MSDS sections (1-16) from KOSHA API
 * This is a heavy operation, so should only be called on user request.
 */
export const fetchKoshaMsds = async (chemId: number): Promise<MsdsSection[]> => {
    const paddedId = String(chemId).padStart(6, '0');
    console.log(`[KOSHA] Fetching Full MSDS for: ${paddedId}`);

    // Define section names (approximately)
    const sectionNames = [
        "1. 화학제품과 회사에 관한 정보",
        "2. 유해성·위험성",
        "3. 구성성분의 명칭 및 함유량",
        "4. 응급조치 요령",
        "5. 폭발·화재시 대처방법",
        "6. 누출 사고시 대처방법",
        "7. 취급 및 저장방법",
        "8. 노출방지 및 개인보호구",
        "9. 물리화학적 특성",
        "10. 안정성 및 반응성",
        "11. 독성에 관한 정보",
        "12. 환경에 미치는 영향",
        "13. 폐기시 주의사항",
        "14. 운송에 필요한 정보",
        "15. 법적 규제현황",
        "16. 그 밖의 참고사항"
    ];

    // Create array of promises for 16 sections
    const promises = Array.from({ length: 16 }, (_, i) => {
        const detailNum = String(i + 1).padStart(2, '0'); // 01, 02, ... 16
        return axios.get(`${BASE_URL}/chemdetail${detailNum}`, {
            params: {
                chemId: paddedId,
                serviceKey: SERVICE_KEY
            }
        }).then(res => ({ idx: i, data: res.data })).catch(e => ({ idx: i, error: e }));
    });

    const results = await Promise.all(promises);

    const sections: MsdsSection[] = [];

    results.forEach((res: any) => {
        if (res.error) {
            console.warn(`[KOSHA] Failed section ${res.idx + 1}`);
            return;
        }

        try {
            const parsed = parser.parse(res.data);
            const items = parsed?.response?.body?.items?.item;

            if (!items) return;

            const list = Array.isArray(items) ? items : [items];

            // Map items to label/value
            const content = list.map((item: any) => ({
                label: item.msdsItemNameKor || 'Unknown',
                value: item.itemDetail || '자료없음'
            }));

            if (content.length > 0) {
                sections.push({
                    title: sectionNames[res.idx] || `Section ${res.idx + 1}`,
                    content: content
                });
            }

        } catch (e) {
            console.warn(`[KOSHA] Parse error section ${res.idx + 1}`, e);
        }
    });

    // Sort by original index to ensure order
    // But since we pushed in loop of results which depends on promise resolution order? No Promise.all preserves order of results array.
    // Wait, Promise.all returns results in order.
    // But I pushed to sections inside forEach which iterates the results array. So it is ordered.
    // Let's just make sure empty sections are handled.

    return sections;
};;

import { supabase } from './supabaseClient';
import type { Lab, LabMember } from '../store/useLabStore';

export const labService = {
    async createLab(name: string, password?: string, nickname?: string): Promise<Lab> {
        const { data: userData } = await supabase.auth.getUser();
        if (!userData.user) throw new Error("Not authenticated");

        // 1. Create Lab
        const { data: labData, error: labError } = await supabase
            .from('labs')
            .insert({
                name,
                created_by: userData.user.id,
                join_password: password || null
            })
            .select()
            .single();

        if (labError) throw labError;

        // 2. Add creator as admin
        const { error: memberError } = await supabase
            .from('lab_members')
            .insert({
                lab_id: labData.id,
                user_id: userData.user.id,
                role: 'admin',
                nickname: nickname || null
            });

        if (memberError) throw memberError;

        return labData as Lab;
    },

    async joinLab(labId: string, role: string = 'researcher', password?: string, nickname?: string): Promise<LabMember> {
        const { data: userData } = await supabase.auth.getUser();
        if (!userData.user) throw new Error("Not authenticated");

        const { error } = await supabase.rpc('join_lab_with_password', {
            target_lab_id: labId,
            joining_user_id: userData.user.id,
            requested_role: role,
            provided_password: password || null,
            p_nickname: nickname || null
        });

        if (error) {
            if (error.message.includes('User is already a member')) {
                const err: any = new Error("이미 이 연구실에 가입되어 있습니다.");
                err.code = '23505'; // keep backward compatibility with existing UI error handling
                throw err;
            }
            throw new Error(error.message === 'Incorrect password' ? '비밀번호가 올바르지 않습니다.' : error.message);
        }

        // Fetch the newly created member to return
        const { data: memberData, error: memberError } = await supabase
            .from('lab_members')
            .select('*, labs(*)')
            .eq('lab_id', labId)
            .eq('user_id', userData.user.id)
            .single();

        if (memberError) throw memberError;
        return memberData as LabMember;
    },

    async getMyLabs(): Promise<LabMember[]> {
        const { data: userData } = await supabase.auth.getUser();
        if (!userData.user) return [];

        const { data, error } = await supabase
            .from('lab_members')
            .select(`
                *,
                lab:labs(*)
            `)
            .eq('user_id', userData.user.id);

        if (error) throw error;
        return data as LabMember[];
    },

    async searchLabs(query: string): Promise<Lab[]> {
        if (!query.trim()) return [];
        const { data, error } = await supabase
            .from('labs')
            .select('*')
            .ilike('name', `%${query}%`)
            .limit(10);

        if (error) throw error;
        return data as Lab[];
    },

    async getLabMembers(labId: string): Promise<{ user_id: string; role: string; joined_at: string; email: string; nickname?: string }[]> {
        const { data, error } = await supabase.rpc('get_lab_members', { target_lab_id: labId });
        if (error) throw error;
        return data || [];
    },

    async updateMemberRole(labId: string, userId: string, newRole: string): Promise<void> {
        const { error } = await supabase.rpc('update_lab_member_role', {
            target_lab_id: labId,
            target_user_id: userId,
            new_role: newRole
        });
        if (error) throw error;
    },

    async removeMember(labId: string, userId: string): Promise<void> {
        const { error } = await supabase.rpc('remove_lab_member', {
            target_lab_id: labId,
            target_user_id: userId
        });
        if (error) throw error;
    },

    async updateLab(labId: string, updates: { name?: string; join_password?: string }): Promise<void> {
        const { error } = await supabase
            .from('labs')
            .update(updates)
            .eq('id', labId);

        if (error) throw error;
    },

    async deleteLab(labId: string): Promise<void> {
        const { error } = await supabase
            .from('labs')
            .delete()
            .eq('id', labId);

        if (error) throw error;
    }
};

/**
 * Media Product Service
 * Handles searching for media products from Supabase
 */

import { supabase } from './supabaseClient';

export interface MediaProduct {
    id: string;
    brand: string | null;
    product_name: string | null;
    product_numbers: string[] | null;
    thumbnail_url: string | null;
    url_slug: string | null;
}

export type SortOption = 'relevance' | 'name_asc' | 'name_desc' | 'brand_asc' | 'brand_desc';

export interface SearchOptions {
    query: string;
    limit?: number;
    brandFilter?: string;
    sortBy?: SortOption;
    exactProductNumber?: boolean;
}

export interface SearchResult {
    products: MediaProduct[];
    brands: string[];  // Unique brands in results for filter UI
    totalCount: number;
}

/**
 * Get list of all unique brands
 */
export async function getAllBrands(): Promise<string[]> {
    try {
        const { data, error } = await supabase
            .from('products')
            .select('brand')
            .not('brand', 'is', null)
            .order('brand');

        if (error) {
            console.error('[MediaProduct] Get brands error:', error);
            return [];
        }

        // Extract unique brands
        const uniqueBrands = [...new Set(data?.map(d => d.brand).filter(Boolean) as string[])];
        return uniqueBrands;
    } catch (error) {
        console.error('[MediaProduct] Get brands failed:', error);
        return [];
    }
}

/**
 * Enhanced search with filtering and sorting
 */
export async function searchMediaProductsAdvanced(options: SearchOptions): Promise<SearchResult> {
    const { query, limit = 20, brandFilter, sortBy = 'relevance', exactProductNumber = false } = options;

    if (!query.trim()) {
        return { products: [], brands: [], totalCount: 0 };
    }

    const searchTerm = query.trim();

    try {
        // If exact product number search
        if (exactProductNumber || /^[A-Za-z0-9\-]+$/.test(searchTerm)) {
            const { data: numberResults, error: numberError } = await supabase
                .from('products')
                .select('*')
                .contains('product_numbers', [searchTerm.toUpperCase()])
                .limit(limit);

            if (!numberError && numberResults && numberResults.length > 0) {
                const brands = [...new Set(numberResults.map(p => p.brand).filter(Boolean) as string[])];
                return { products: numberResults, brands, totalCount: numberResults.length };
            }
        }

        // Build product query
        let queryBuilder = supabase.from('products').select('*', { count: 'exact' });

        // Search condition
        queryBuilder = queryBuilder.or(
            `product_name.ilike.%${searchTerm}%,brand.ilike.%${searchTerm}%`
        );

        // Brand filter
        if (brandFilter && brandFilter !== 'all') {
            queryBuilder = queryBuilder.eq('brand', brandFilter);
        }

        // Sorting
        switch (sortBy) {
            case 'name_asc':
                queryBuilder = queryBuilder.order('product_name', { ascending: true });
                break;
            case 'name_desc':
                queryBuilder = queryBuilder.order('product_name', { ascending: false });
                break;
            case 'brand_asc':
                queryBuilder = queryBuilder.order('brand', { ascending: true });
                break;
            case 'brand_desc':
                queryBuilder = queryBuilder.order('brand', { ascending: false });
                break;
            default:
                // relevance - no specific order, Supabase returns by match
                break;
        }

        queryBuilder = queryBuilder.limit(limit);

        // Build separate query to get ALL brands matching the search term
        // This ensures the filter dropdown shows all relevant brands, not just those in the current page
        let brandQuery = supabase.from('products').select('brand');
        brandQuery = brandQuery.or(
            `product_name.ilike.%${searchTerm}%,brand.ilike.%${searchTerm}%`
        );
        brandQuery = brandQuery.not('brand', 'is', null);
        // We do NOT apply the brandFilter or limit to this query

        // Execute both queries in parallel
        const [productResponse, brandResponse] = await Promise.all([
            queryBuilder,
            brandQuery
        ]);

        const { data, error, count } = productResponse;

        if (error) {
            console.error('[MediaProduct] Advanced search error:', error);
            return { products: [], brands: [], totalCount: 0 };
        }

        // Extract unique brands from the brand query (unlimited)
        // Fallback to product results if brand query fails (though unlikely)
        const brandSource = brandResponse.data || data || [];
        const brands = [...new Set(brandSource.map(p => p.brand).filter(Boolean) as string[])].sort();

        return {
            products: data || [],
            brands,
            totalCount: count || 0
        };
    } catch (error) {
        console.error('[MediaProduct] Advanced search failed:', error);
        return { products: [], brands: [], totalCount: 0 };
    }
}

/**
 * Simple search (backward compatible)
 */
export async function searchMediaProducts(query: string, limit: number = 10): Promise<MediaProduct[]> {
    const result = await searchMediaProductsAdvanced({ query, limit });
    return result.products;
}

/**
 * Search by exact product number
 */
export async function searchByProductNumber(productNumber: string): Promise<MediaProduct | null> {
    if (!productNumber.trim()) {
        return null;
    }

    try {
        const { data, error } = await supabase
            .from('products')
            .select('*')
            .contains('product_numbers', [productNumber.trim().toUpperCase()])
            .limit(1);

        if (error) {
            console.error('[MediaProduct] Product number search error:', error);
            return null;
        }

        return data && data.length > 0 ? data[0] : null;
    } catch (error) {
        console.error('[MediaProduct] Search by product number failed:', error);
        return null;
    }
}

import type { Chemical } from '../types';
import { COMMON_CHEMICALS } from '../data/commonChemicals';

const PUBCHEM_BASE_URL = 'https://pubchem.ncbi.nlm.nih.gov/rest/pug';
const PUBCHEM_VIEW_URL = 'https://pubchem.ncbi.nlm.nih.gov/rest/pug_view/data/compound';

/**
 * Fetch GHS Safety Data (Signal, Hazard Statements) from PubChem PUG View API
 */
const fetchGHSData = async (cid: string | number): Promise<Chemical['ghs'] | undefined> => {
    try {
        const url = `${PUBCHEM_VIEW_URL}/${cid}/JSON?heading=GHS+Classification`;
        const response = await fetch(url);

        if (!response.ok) return undefined;

        const data = await response.json();

        // Navigate deep JSON structure safely
        // Record -> Section -> ... -> Information -> Name: "Signal" / "GHS Hazard Statements"

        // 1. Find the "Safety and Hazards" section (usually handled by ?heading=GHS+Classification, but structure varies)
        // Ensure we are in the right Record
        const sections = data.Record?.Section;
        if (!sections) return undefined;

        // Recursive helper to find "GHS Classification" section or specific Info
        // However, with ?heading=GHS+Classification, the response is usually trimmed to that section.
        // The structure usually is:
        // Section[0] -> "Safety and Hazards" -> Section -> "Hazards Identification" -> Section -> "GHS Classification"

        // Let's search for "Information" array directly inside the first section tree
        // Or flattener approach

        let signal = '';
        const hazardStatements: string[] = [];
        const pictograms: string[] = [];

        // Helper to traverse and extract
        const traverse = (node: any) => {
            if (node.Information) {
                for (const info of node.Information) {
                    if (info.Name === 'Signal') {
                        signal = info.Value?.StringWithMarkup?.[0]?.String || '';
                    }
                    if (info.Name === 'GHS Hazard Statements') {
                        // Value can be StringWithMarkup array
                        if (info.Value?.StringWithMarkup) {
                            info.Value.StringWithMarkup.forEach((s: any) => {
                                if (s.String) hazardStatements.push(s.String);
                            });
                        }
                    }
                    if (info.Name === 'Pictogram(s)') {
                        if (info.Value?.StringWithMarkup) {
                            info.Value.StringWithMarkup.forEach((s: any) => {
                                // Extract from Markup -> URL
                                if (s.Markup) {
                                    s.Markup.forEach((m: any) => {
                                        if (m.URL) pictograms.push(m.URL);
                                    });
                                }
                            });
                        }
                    }
                }
            }
            if (node.Section) {
                node.Section.forEach(traverse);
            }
        };

        traverse(data.Record);

        // if (!signal && hazardStatements.length === 0) return undefined; // Let's return even if only pictograms found, though unlikely

        return {
            signal: signal || 'Warning', // Default if found statements but no signal
            hazardStatements: [...new Set(hazardStatements)], // Dedupe
            pictograms: [...new Set(pictograms)]
        };

    } catch (e) {
        console.warn('Failed to fetch GHS data', e);
        return undefined;
    }
};

/**
 * Fetch Synonyms to find CAS Number
 */
const fetchSynonyms = async (cid: string | number): Promise<string[]> => {
    try {
        const url = `${PUBCHEM_BASE_URL}/compound/cid/${cid}/synonyms/JSON`;
        const response = await fetch(url);
        if (!response.ok) return [];

        const data = await response.json();
        return data.InformationList?.Information?.[0]?.Synonym || [];
    } catch (e) {
        console.warn('Failed to fetch synonyms', e);
        return [];
    }
};

export const fetchChemicalInfo = async (query: string): Promise<Chemical | null> => {
    if (!query) return null;

    // 1. Check Local Dataset first (O(1) lookup)
    const normalizedQuery = query.trim().toUpperCase();
    if (COMMON_CHEMICALS[normalizedQuery]) {
        console.log(`[Cache Hit] Found ${query} in local dataset.`);
        return COMMON_CHEMICALS[normalizedQuery];
    }

    try {
        // 2. PubChem API Logic
        const url = `${PUBCHEM_BASE_URL}/compound/name/${encodeURIComponent(query)}/property/MolecularFormula,MolecularWeight,IUPACName,Title,CanonicalSMILES/JSON`;

        const response = await fetch(url);

        if (!response.ok) {
            if (response.status === 404) {
                console.warn(`Chemical not found in PubChem: ${query}`);
                return null;
            }
            throw new Error(`PubChem API Error: ${response.statusText}`);
        }

        const data = await response.json();
        const compoundProps = data.PropertyTable?.Properties?.[0];

        if (!compoundProps) {
            return null;
        }

        const cid = compoundProps.CID;

        // 3. Fetch GHS Data, Physical Properties, and Synonyms in parallel
        const [ghsData, physicalProps, synonyms] = await Promise.all([
            fetchGHSData(cid),
            fetchPhysicalProperties(cid),
            fetchSynonyms(cid)
        ]);

        // Find CAS Number from synonyms (Pattern: d-dd-d where d is digit, but usually 2-7 digits first)
        // Strict CAS pattern: \d{2,7}-\d{2}-\d
        const casPattern = /^\d{2,7}-\d{2}-\d$/;
        // Find the first synonym that matches the CAS pattern
        const foundCas = synonyms.find((s: string) => casPattern.test(s));

        // Name Priority: Title (Common Name) > Uppercase Query (if matched) > IUPACName > Query
        let displayName = compoundProps.Title || compoundProps.IUPACName || query;

        return {
            id: String(cid || Date.now()),
            name: displayName,
            // Use found CAS or fallback to query if it looks like a CAS, otherwise just empty or query?
            // User complained query "AgHO" became CAS.
            // If no CAS found, maybe we shouldn't show the query as CAS unless it looks like one.
            casNumber: foundCas || (casPattern.test(query) ? query : displayName),
            molecularFormula: compoundProps.MolecularFormula,
            molecularWeight: parseFloat(compoundProps.MolecularWeight),
            properties: {
                isOrganic: compoundProps.MolecularFormula?.includes('C'),
                isHalogenated: false, // Analyzer determines this
            },
            physicalProperties: physicalProps,
            ghs: ghsData
        };

    } catch (error) {
        console.error("Failed to fetch chemical info:", error);
        return null; // Return null on network error to allow manual retry or handling
    }
};

/**
 * Fetch Physical Properties and Stability info from PubChem PUG View API
 */
const fetchPhysicalProperties = async (cid: string | number): Promise<Chemical['physicalProperties'] | undefined> => {
    try {
        const url = `${PUBCHEM_VIEW_URL}/${cid}/JSON?heading=Chemical+and+Physical+Properties`;
        // Note: Stability info is often in a separate section "Stability and Reactivity", but let's try to fetch broadly or separate calls.
        // Actually PUG View API allows full record or specific headings. "Stability+and+Reactivity" is another heading.
        // Let's try fetching the full record is too big. Let's make parallel calls or one smart call if possible.
        // PUG View doesn't support multi-heading in one param easily usually, but let's try separately for Stability.

        const [propsResponse, stabilityResponse] = await Promise.all([
            fetch(url),
            fetch(`${PUBCHEM_VIEW_URL}/${cid}/JSON?heading=Stability+and+Reactivity`)
        ]);

        const propsData = propsResponse.ok ? await propsResponse.json() : {};
        const stabilityData = stabilityResponse.ok ? await stabilityResponse.json() : {};

        const result: Chemical['physicalProperties'] = {};

        // Helper to find specific localized props
        // Section -> Chemical and Physical Properties -> Experimental Properties -> ...

        const extractValue = (record: any, sectionName: string): string | undefined => {
            let foundVal: string | undefined;
            const traverse = (node: any) => {
                if (foundVal) return;

                if (node.TOCHeading === sectionName && node.Information) {
                    // Get the first good String value
                    for (const info of node.Information) {
                        if (info.Value?.StringWithMarkup?.[0]?.String) {
                            foundVal = info.Value.StringWithMarkup[0].String;
                            return;
                        }
                        if (info.Value?.StringWithMarkup?.[0]?.Value) { // specific case
                            foundVal = info.Value.StringWithMarkup[0].Value;
                            return;
                        }
                    }
                }
                if (node.Section) {
                    node.Section.forEach(traverse);
                }
            };
            traverse(record.Record);
            return foundVal;
        };

        // 1. Solubility
        const solubilityRaw = extractValue(propsData, 'Solubility');
        if (solubilityRaw) {
            result.solubility = solubilityRaw; // e.g. "Miscible with water", "Insoluble"
        }

        // 2. Flash Point
        const fpRaw = extractValue(propsData, 'Flash Point');
        if (fpRaw) {
            // Parse "12 deg C", "-20 C", "54 F"
            // We need C.
            const match = fpRaw.match(/(-?[\d.]+)\s*°?\s*C/i);
            if (match) {
                result.flashPoint = parseFloat(match[1]);
            }
        }

        // 3. Boiling Point
        const bpRaw = extractValue(propsData, 'Boiling Point');
        if (bpRaw) {
            const match = bpRaw.match(/(-?[\d.]+)\s*°?\s*C/i);
            if (match) {
                result.boilingPoint = parseFloat(match[1]);
            }
        }

        // 4. Log Kow (Octanol/Water Partition Coefficient)
        const logPRaw = extractValue(propsData, 'Octanol/Water Partition Coefficient');
        if (logPRaw) {
            const match = logPRaw.match(/(-?[\d.]+)/);
            if (match) {
                result.logKow = parseFloat(match[1]);
            }
        }

        // 5. Stability
        // Extract from stabilityData -> Section "Stability and Reactivity" -> "Reactivity Profile" or "Stability"
        // Let's grab "Stability/Shelf Life" or "Stability"
        const traverseStability = (node: any) => {
            if (result.stability) return;
            // Look for keywords in any info under Stability headers
            if (node.TOCHeading === 'Stability' || node.TOCHeading === 'Stability/Shelf Life' || node.TOCHeading === 'Reactivity Profile') {
                if (node.Information) {
                    for (const info of node.Information) {
                        const text = info.Value?.StringWithMarkup?.[0]?.String || '';
                        if (text) {
                            // Just take the first meaningful description
                            result.stability = text;
                            return;
                        }
                    }
                }
            }
            if (node.Section) node.Section.forEach(traverseStability);
        };
        if (stabilityData.Record) {
            traverseStability(stabilityData.Record);
        }

        return result;

    } catch (e) {
        console.warn('Failed to fetch physical properties', e);
        return undefined;
    }
};

/**
 * Fetches Safety and Hazards data from PubChem to emulate MSDS content.
 */
import type { MsdsSection } from '../types';

export const fetchPubChemMsds = async (cid: string | number): Promise<MsdsSection[]> => {
    try {
        const url = `${PUBCHEM_VIEW_URL}/${cid}/JSON?heading=Safety+and+Hazards`;
        const response = await fetch(url);

        if (!response.ok) return [];

        const data = await response.json();
        const rootSection = data.Record?.Section?.[0]; // Usually "Safety and Hazards"

        if (!rootSection || !rootSection.Section) return [];

        const sections: MsdsSection[] = [];

        // Recursive helper to flatten content of a section
        const extractContent = (node: any): { label: string; value: string }[] => {
            const items: { label: string; value: string }[] = [];

            if (node.Information) {
                node.Information.forEach((info: any) => {
                    const label = info.Name || info.Description || 'Info';
                    let value = '';

                    // Special handling for Pictograms to get image URLs
                    if (label === 'Pictogram(s)' && info.Value?.StringWithMarkup) {
                        const urls: string[] = [];
                        info.Value.StringWithMarkup.forEach((s: any) => {
                            if (s.Markup) {
                                s.Markup.forEach((m: any) => {
                                    if (m.URL) urls.push(m.URL);
                                });
                            }
                        });
                        if (urls.length > 0) {
                            value = urls.join('|');
                        }
                    }

                    // Standard text fallback if value not set yet
                    if (!value) {
                        if (info.Value?.StringWithMarkup) {
                            value = info.Value.StringWithMarkup.map((s: any) => s.String).join('\n');
                        } else if (info.Value?.Number) {
                            value = String(info.Value.Number);
                        }
                    }

                    if (value) {
                        items.push({ label, value });
                    }
                });
            }

            if (node.Section) {
                node.Section.forEach((sub: any) => {
                    // If subsection has its own heading, maybe add it as a label prefix?
                    // Or just flatten it.
                    const subItems = extractContent(sub);
                    subItems.forEach(item => {
                        items.push({
                            label: `${sub.TOCHeading} - ${item.label}`,
                            value: item.value
                        });
                    });
                });
            }
            return items;
        };

        // Root sections under "Safety and Hazards" are usually:
        // 1. Hazards Identification
        // 2. First Aid Measures
        // 3. Fire Fighting Measures
        // ...

        rootSection.Section.forEach((sec: any) => {
            const content = extractContent(sec);
            if (content.length > 0) {
                sections.push({
                    title: sec.TOCHeading,
                    content: content
                });
            }
        });

        return sections;

    } catch (e) {
        console.warn('[PubChem] Failed to fetch MSDS data', e);
        return [];
    }
};
